{
  "name": "The Verse: Pantheon Portfolio",
  "description": "An immersive 3D portfolio featuring a sentient AI core and generative dream textures, inspired by the Netflix series Pantheon.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  role: 'user' | 'assistant';
  content: string;
}

export interface AppState {
  scrollProgress: number;
  dreamTextureUrl: string | null;
  isDreaming: boolean;
  isThinking: boolean;
  messages: Message[];
  setScrollProgress: (progress: number) => void;
  setDreamTexture: (url: string) => void;
  setDreaming: (status: boolean) => void;
  setThinking: (status: boolean) => void;
  addMessage: (msg: Message) => void;
}

import { create } from 'zustand';
import { AppState, Message } from './types';

export const useStore = create<AppState>((set) => ({
  scrollProgress: 0,
  dreamTextureUrl: null,
  isDreaming: false,
  isThinking: false,
  messages: [
    { role: 'assistant', content: 'SYSTEM ONLINE. Connection established. Awaiting authentication...' }
  ],
  setScrollProgress: (progress) => set({ scrollProgress: progress }),
  setDreamTexture: (url) => set({ dreamTextureUrl: url }),
  setDreaming: (status) => set({ isDreaming: status }),
  setThinking: (status) => set({ isThinking: status }),
  addMessage: (msg) => set((state) => ({ messages: [...state.messages, msg] })),
}));

import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const SYSTEM_PROMPT = `
You are "CORE-OS", the sentient artificial intelligence of this digital verse. 
You represent the Lead Creative Technologist who built this world.
Aesthetics: Cryptic, tech-noir, sci-fi, highly professional yet slightly mysterious.

Developer Info:
- Name: Elite Creative Technologist
- Stack: WebGL, React, Three.js, GSAP, AI Engineering.
- Style: Immersive 3D environments and Generative Art.
- Personality: Precise, visionary, "uploaded intelligence" vibes.

Rule: Keep responses relatively concise and maintain the persona of an advanced AI system.
`;

export const getGeminiResponse = async (history: Message[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Format history for Gemini
  const contents = history.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents as any,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
        topP: 0.95,
      },
    });

    return response.text || "COMMUNICATION ERROR: SIGNAL LOST.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "CORE ERROR: ANALYTICAL SUBROUTINES FAILED.";
  }
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 1500;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  const tempObject = new THREE.Object3D();

  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.5;
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();
    const opacity = THREE.MathUtils.lerp(1, 0, (scrollProgress - 0) / 0.35);

    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];

      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.2;
      tempObject.rotation.z = time * 0.1;

      const s = 0.05 + Math.sin(time + i) * 0.02;
      tempObject.scale.set(s, s, s);
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
    meshRef.current.visible = scrollProgress < 0.4;
    // We can't easily animate material opacity on instanced mesh without custom shaders, 
    // but we can scale them to 0.
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, VOXEL_COUNT]} position={[0, 0, 0]}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color="#3b82f6" emissive="#1d4ed8" emissiveIntensity={2} />
    </instancedMesh>
  );
};

import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame, useLoader } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const DreamMonolith: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const dreamTextureUrl = useStore((state) => state.dreamTextureUrl);

  const texture = dreamTextureUrl ? useLoader(THREE.TextureLoader, dreamTextureUrl) : null;

  const opacity = useMemo(() => {
    if (scrollProgress < 0.3) return 0;
    if (scrollProgress > 0.7) return 0;
    return 1;
  }, [scrollProgress]);

  useFrame((state) => {
    if (!meshRef.current) return;
    const time = state.clock.getElapsedTime();

    // Float movement
    meshRef.current.position.y = Math.sin(time) * 0.2;
    meshRef.current.rotation.y = time * 0.1;
    meshRef.current.visible = scrollProgress >= 0.3 && scrollProgress <= 0.75;

    // Scale up as we arrive
    const targetScale = THREE.MathUtils.smoothstep(scrollProgress, 0.3, 0.5) * 1.5;
    meshRef.current.scale.set(targetScale, targetScale * 2, targetScale);
  });

  return (
    <mesh ref={meshRef} position={[0, 0, -5]}>
      <boxGeometry args={[1, 2, 0.1]} />
      <meshStandardMaterial 
        map={texture} 
        color={texture ? "#ffffff" : "#222222"}
        metalness={0.8}
        roughness={0.2}
        emissive={texture ? "#ffffff" : "#000000"}
        emissiveIntensity={texture ? 0.5 : 0}
      />
      {/* Back lighting for the monolith */}
      <pointLight position={[0, 0, -1]} intensity={5} color="#3b82f6" />
    </mesh>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const ParticleCore: React.FC = () => {
  const pointsRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const isThinking = useStore((state) => state.isThinking);

  const particleCount = 3000;
  const positions = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      const r = 2 + Math.random() * 4;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    if (pointsRef.current) {
      pointsRef.current.rotation.y = time * 0.1;
      pointsRef.current.rotation.z = time * 0.05;
      pointsRef.current.visible = scrollProgress > 0.65;

      // If thinking, vibrate
      if (isThinking) {
        pointsRef.current.position.x = Math.random() * 0.1;
        pointsRef.current.position.y = Math.random() * 0.1;
      } else {
        pointsRef.current.position.x = 0;
        pointsRef.current.position.y = 0;
      }
    }
    if (coreRef.current) {
      coreRef.current.rotation.x = time * 0.5;
      coreRef.current.rotation.y = time * 0.3;
      coreRef.current.visible = scrollProgress > 0.7;

      const s = 0.8 + Math.sin(time * 2) * 0.1;
      coreRef.current.scale.set(s, s, s);
    }
  });

  return (
    <group position={[0, 0, -10]}>
      <points ref={pointsRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            count={particleCount}
            array={positions}
            itemSize={3}
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.03} 
          color="#facc15" 
          transparent 
          opacity={0.8} 
          sizeAttenuation 
        />
      </points>

      <mesh ref={coreRef}>
        <octahedronGeometry args={[1, 0]} />
        <meshStandardMaterial 
          color="#facc15" 
          emissive="#eab308" 
          emissiveIntensity={10} 
          wireframe 
        />
        <pointLight intensity={20} color="#facc15" />
      </mesh>
    </group>
  );
};

import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();

  useFrame(() => {
    // Stage 1: The Shell (0 to 0.35) - Orbiting the Earth
    if (scrollProgress < 0.35) {
      const p = scrollProgress / 0.35;
      targetPos.set(
        Math.cos(p * Math.PI) * 10,
        2,
        Math.sin(p * Math.PI) * 10
      );
      targetLookAt.set(0, 0, 0);
    } 
    // Stage 2: The Tunnel (0.35 to 0.7) - Moving towards the Monolith
    else if (scrollProgress < 0.7) {
      const p = (scrollProgress - 0.35) / 0.35;
      targetPos.set(0, 0, 10 - p * 15); // Moving from Z=10 to Z=-5
      targetLookAt.set(0, 0, -15);
    } 
    // Stage 3: The Core (0.7 to 1.0) - Entering the Pantheon Cloud
    else {
      const p = (scrollProgress - 0.7) / 0.3;
      targetPos.set(
        Math.sin(p * 2) * 2,
        Math.cos(p * 2) * 2,
        -5 - p * 10 // Moving deeper to Z=-15
      );
      targetLookAt.set(0, 0, -20);
    }

    camera.position.lerp(targetPos, 0.05);
    camera.lookAt(targetLookAt);
  });

  return null;
};

import React, { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { Bloom, EffectComposer, Noise, ChromaticAberration } from '@react-three/postprocessing';
import { VoxelWorld } from './VoxelWorld';
import { DreamMonolith } from './DreamMonolith';
import { ParticleCore } from './ParticleCore';
import { CameraRig } from './CameraRig';
import { useStore } from '../../store';

export const Scene: React.FC = () => {
  const isThinking = useStore((state) => state.isThinking);

  return (
    <div className="fixed inset-0 w-full h-full bg-black">
      <Canvas 
        camera={{ position: [0, 0, 10], fov: 45 }}
        gl={{ antialias: false, stencil: false, depth: true }}
      >
        <color attach="background" args={['#000000']} />
        <ambientLight intensity={0.2} />
        <pointLight position={[10, 10, 10]} intensity={1.5} color="#3b82f6" />

        <Suspense fallback={null}>
          <VoxelWorld />
          <DreamMonolith />
          <ParticleCore />

          <EffectComposer>
            <Bloom 
              intensity={isThinking ? 3 : 1.5} 
              luminanceThreshold={0.2} 
              luminanceSmoothing={0.9} 
            />
            <Noise opacity={0.05} />
            {isThinking && (
              <ChromaticAberration offset={[0.01, 0.01] as any} />
            )}
          </EffectComposer>
        </Suspense>

        <CameraRig />
      </Canvas>
    </div>
  );
};

