    if (ringRef.current) {
      ringRef.current.visible = visible;
      ringRef.current.rotation.z = time * 0.2;
      ringRef.current.position.z = -30;

      // Floating motion
      ringRef.current.position.y = Math.sin(time * 0.5) * 0.5;
    }

    if (coreRef.current) {
      coreRef.current.visible = visible;
      coreRef.current.rotation.x = time * 0.5;
      coreRef.current.rotation.y = time * 0.3;
