    const s = 0.02 + Math.sin(time * 5 + z) * 0.01;
    meshRef.current.scale.set(s, s, length);
  });

  const x = Math.cos(angle) * radius;
  const y = Math.sin(angle) * radius;

  return (
    <mesh ref={meshRef} position={[x, y, z]}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color="#d946ef" emissive="#a855f7" emissiveIntensity={15} transparent opacity={0.3} />
    </mesh>
