import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();

  useFrame(() => {
    // Stage 1: The Shell (0.0 - 0.25)
    if (scrollProgress < 0.25) {
      const p = scrollProgress / 0.25;
      targetPos.set(
        Math.cos(p * Math.PI) * 10,
        2,
        Math.sin(p * Math.PI) * 10
      );
      targetLookAt.set(0, 0, 0);
    } 
    // Stage 2: The Manifestation (0.25 - 0.5)
    else if (scrollProgress < 0.5) {
      const p = (scrollProgress - 0.25) / 0.25;
      targetPos.set(0, 1, 10 - p * 15); 
      targetLookAt.set(0, 0, -10);
    } 
    // Stage 3: The Core (0.5 - 0.75)
    else if (scrollProgress < 0.75) {
      const p = (scrollProgress - 0.5) / 0.25;
      targetPos.set(
        Math.sin(p * 4) * 3,
        Math.cos(p * 4) * 3,
        -5 - p * 10
      );
      targetLookAt.set(0, 0, -15);
    }
    // Stage 4: The Singularity (0.75 - 1.0)
    else {
      const p = (scrollProgress - 0.75) / 0.25;
      // Faster zoom into the violet void
      targetPos.set(0, 0, -15 - p * 15);
      targetLookAt.set(0, 0, -40);

      // Dramatic camera tilt
      camera.rotation.z = p * Math.PI * 0.2;
    }

    camera.position.lerp(targetPos, 0.05);
    camera.lookAt(targetLookAt);
  });

  return null;
};

