import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2000;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.5 + (Math.random() > 0.95 ? 1.5 : 0);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.3;
    meshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    if (!visibility) return;

    // Enhanced Core Pulse
    const pulseSpeed = 3.5;
    const pulse = 1 + Math.sin(time * pulseSpeed) * 0.15;
    coreRef.current.scale.set(pulse, pulse, pulse);
    (coreRef.current.material as THREE.MeshStandardMaterial).emissiveIntensity = 4 + Math.sin(time * 6) * 2;

    // Energy Shell Pulse
    const shellPulse = 1.1 + Math.sin(time * 2) * 0.05;
    shellRef.current.scale.set(shellPulse, shellPulse, shellPulse);
    shellRef.current.rotation.y = time * 0.5;
    shellRef.current.rotation.x = time * 0.3;

    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];

      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.1;

      const offset = Math.sin(time + i) * 0.05;
      tempObject.position.addScalar(offset);

      // Dynamic scaling based on distance and pulse
      const distPulse = Math.sin(time * 2 + (x+y+z)) * 0.02;
      const s = (i % 5 === 0 ? 0.08 : 0.04) * (1 - scrollProgress * 3.3) + distPulse;
      const finalScale = Math.max(0, s);
      tempObject.scale.set(finalScale, finalScale, finalScale);
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <group>
      <instancedMesh ref={meshRef} args={[undefined as any, undefined as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#3b82f6" emissive="#1e40af" emissiveIntensity={5} />
      </instancedMesh>

      <mesh ref={coreRef}>
        <sphereGeometry args={[2, 32, 32]} />
