      camera.fov = 45 + easedP * 30; // Increasing FOV for speed sensation
      camera.updateProjectionMatrix();
    }

    // Adjusted lerp factor for "weighty" cinematic feel
    const lerpFactor = scrollProgress > 0.9 ? 0.03 : 0.06;
    camera.position.lerp(targetPos, lerpFactor);

    // Instead of direct lookAt which can be snappy, we could lerp a target lookAt point
    // but the position lerp already provides most of the smoothing.
    camera.lookAt(targetLookAt);
  });

  return null;
};

import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

// Easing function for smoother transitions
const easeInOutCubic = (t: number) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();

  useFrame(() => {
    // Smoother transitions using multi-stage scroll segments

    // Level 1: The Shell (0.0 - 0.25)
    if (scrollProgress < 0.25) {
      const p = scrollProgress / 0.25;
      targetPos.set(
        Math.cos(p * Math.PI * 0.5) * 10,
        2 + Math.sin(p * Math.PI) * 1,
        Math.sin(p * Math.PI * 0.5) * 10
      );
      targetLookAt.set(0, 0, 0);
    } 
    // Level 2: The Manifestation (0.25 - 0.5)
    else if (scrollProgress < 0.5) {
      const p = (scrollProgress - 0.25) / 0.25;
      targetPos.set(0, 1, 10 - p * 15); 
      targetLookAt.set(0, 0, -10);
    } 
    // Level 3: The Core (0.5 - 0.75)
    else if (scrollProgress < 0.75) {
      const p = (scrollProgress - 0.5) / 0.25;
      targetPos.set(
        Math.sin(p * Math.PI * 2) * 3,
        Math.cos(p * Math.PI * 2) * 2,
        -5 - p * 10
      );
      targetLookAt.set(0, 0, -15);
    }
    // Level 4: HyperVoid (0.75 - 0.85)
    else if (scrollProgress < 0.85) {
      const p = (scrollProgress - 0.75) / 0.1;
      targetPos.set(0, 0, -15 - p * 10);
      targetLookAt.set(0, 0, -35);
      camera.rotation.z = p * Math.PI * 0.1;
    }
    // Level 5: Deep Void (0.85 - 0.95)
    else if (scrollProgress < 0.85) {
      const p = (scrollProgress - 0.85) / 0.1;
      const easedP = easeInOutCubic(p);
      targetPos.set(
        Math.sin(easedP * 0.5) * 2,
        Math.cos(easedP * 0.5) * 2,
        -25 - easedP * 20
      );
      targetLookAt.set(0, 0, -55);
      camera.rotation.z = 0.1 * Math.PI + easedP * Math.PI * 0.1;
    }
    // Final: Beyond (0.95 - 1.0)
    else {
      const p = (scrollProgress - 0.95) / 0.05;
      const easedP = easeInOutCubic(p);
      // Final cinematic push into infinity
      targetPos.set(0, 0, -45 - easedP * 40);
      targetLookAt.set(0, 0, -120);
      camera.rotation.z = 0.2 * Math.PI + easedP * 0.3;

      // Fix: Check if camera is a PerspectiveCamera before accessing fov and updateProjectionMatrix
      if (camera instanceof THREE.PerspectiveCamera) {
        camera.fov = 45 + easedP * 30; // Increasing FOV for speed sensation
        camera.updateProjectionMatrix();
      }
    }

    // Adjusted lerp factor for "weighty" cinematic feel
    const lerpFactor = scrollProgress > 0.9 ? 0.03 : 0.06;
    camera.position.lerp(targetPos, lerpFactor);

    // Instead of direct lookAt which can be snappy, we could lerp a target lookAt point
    // but the position lerp already provides most of the smoothing.
    camera.lookAt(targetLookAt);
  });

  return null;
};

import React, { useEffect, useRef, useState } from 'react';
import { useStore } from '../store';

export const SoundSystem: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const audioCtx = useRef<AudioContext | null>(null);
  const gainNode = useRef<GainNode | null>(null);
  const filterNode = useRef<BiquadFilterNode | null>(null);
  const [isStarted, setIsStarted] = useState(false);

  const initAudio = () => {
    if (audioCtx.current) return;

    audioCtx.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    gainNode.current = audioCtx.current.createGain();
    filterNode.current = audioCtx.current.createBiquadFilter();

    filterNode.current.type = 'lowpass';
    filterNode.current.frequency.value = 1000;
    filterNode.current.Q.value = 1;

    gainNode.current.gain.value = 0;

    filterNode.current.connect(gainNode.current);
    gainNode.current.connect(audioCtx.current.destination);

    // Deep Hum Oscillator
    const osc1 = audioCtx.current.createOscillator();
    osc1.type = 'sine';
    osc1.frequency.value = 55; // A1
    osc1.connect(filterNode.current);
    osc1.start();

    // Textural Drone Oscillator
    const osc2 = audioCtx.current.createOscillator();
    osc2.type = 'sawtooth';
    osc2.frequency.value = 55.44; // Slightly detuned
    const subGain = audioCtx.current.createGain();
    subGain.gain.value = 0.2;
    osc2.connect(subGain);
    subGain.connect(filterNode.current);
    osc2.start();

    setIsStarted(true);
  };

  useEffect(() => {
    if (!isStarted || !gainNode.current || !filterNode.current || !audioCtx.current) return;

    // Volume curves: quiet at start, louder in void
    const baseVolume = 0.05 + (scrollProgress * 0.1);
    // Peak volume in the Deep Void (0.85 - 0.95)
    const voidFocus = Math.max(0, 1 - Math.abs(scrollProgress - 0.9) * 10);
    const targetGain = baseVolume + (voidFocus * 0.2);

    // Filter curves: muffled at start, opening up, then deep resonance in void
    const targetFreq = 200 + (scrollProgress * 800) - (voidFocus * 400);

    gainNode.current.gain.setTargetAtTime(targetGain, audioCtx.current.currentTime, 0.1);
    filterNode.current.frequency.setTargetAtTime(targetFreq, audioCtx.current.currentTime, 0.1);
    filterNode.current.Q.setTargetAtTime(1 + (voidFocus * 10), audioCtx.current.currentTime, 0.1);

  }, [scrollProgress, isStarted]);

  return (
    <div className="fixed top-4 right-4 z-50">
      {!isStarted ? (
        <button 
          onClick={initAudio}
          className="bg-blue-900/40 border border-blue-500/50 px-3 py-1 text-[10px] text-blue-400 hover:bg-blue-500 hover:text-white transition-all tracking-tighter"
        >
          INITIALIZE_AUDIO_FEED
        </button>
      ) : (
        <div className="flex items-center gap-2 opacity-30">
          <div className="flex gap-0.5 h-3 items-end">
            {[1,2,3,4].map(i => (
              <div 
                key={i} 
                className="w-1 bg-blue-500 animate-pulse" 
                style={{ height: `${20 + Math.random() * 80}%`, animationDelay: `${i * 0.1}s` }} 
              />
            ))}
          </div>
          <span className="text-[8px] text-blue-500 font-bold">AUDIO_SYNC_ACTIVE</span>
        </div>
      )}
    </div>
  );
};

