        <div className="w-32 h-1 bg-blue-900/30 overflow-hidden">
          <div 
            className="h-full bg-blue-400 transition-all duration-300" 
            style={{ width: `${useStore.getState().scrollProgress * 100}%` }} 
          />
        </div>
        <span>SYSTEM_DEPTH_TRACKER</span>
      </div>
    </div>
  );
};

