import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const HyperVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const gateRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Mesh>(null);

  const shardCount = 60;
  const shards = useMemo(() => {
    const arr = [];
    for (let i = 0; i < shardCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      const radius = 5 + Math.random() * 15;
      arr.push({
        angle,
        radius,
        speed: 0.1 + Math.random() * 0.2,
        z: -20 - Math.random() * 40,
        size: 0.2 + Math.random() * 0.5,
      });
    }
    return arr;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.72 && scrollProgress < 0.95;

    if (gateRef.current) {
      gateRef.current.visible = visible;
      gateRef.current.rotation.z = time * 0.2;
      gateRef.current.rotation.y = Math.sin(time * 0.5) * 0.1;
      gateRef.current.position.z = -30;
    }

    if (coreRef.current) {
      coreRef.current.visible = visible;
      coreRef.current.rotation.x = time * 1.2;
      coreRef.current.rotation.y = time * 0.8;
      const s = 1.5 + Math.sin(time * 5) * 0.4;
      coreRef.current.scale.set(s, s, s);
    }
  });

  return (
    <group>
      <group ref={gateRef}>
        <mesh rotation={[0, 0, 0]}>
          <torusGeometry args={[12, 0.1, 8, 4]} />
          <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={5} wireframe />
        </mesh>
        <mesh rotation={[0, 0, Math.PI / 4]}>
          <torusGeometry args={[11, 0.05, 16, 100]} />
          <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={3} transparent opacity={0.3} />
        </mesh>

        {[0, 1, 2].map((i) => (
          <mesh key={i} rotation={[0, 0, (i * Math.PI) / 1.5]}>
            <boxGeometry args={[15, 0.1, 0.5]} />
            <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={1} transparent opacity={0.2} />
          </mesh>
        ))}
      </group>

      <mesh ref={coreRef} position={[0, 0, -35]}>
        <octahedronGeometry args={[1, 0]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissive="#ffea00" 
          emissiveIntensity={100} 
          roughness={0}
          metalness={1}
        />
        <pointLight intensity={300} color="#ffea00" distance={70} decay={1.5} />
      </mesh>

      <group position={[0, 0, -25]}>
        {shards.map((shard, i) => (
          <Shard key={i} {...shard} />
        ))}
      </group>
    </group>
  );
};

const Shard: React.FC<any> = ({ angle, radius, speed, z, size }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  useFrame((state) => {
    if (!meshRef.current) return;
    const time = state.clock.getElapsedTime();
    meshRef.current.position.z = ((z + time * speed * 50) % 60) - 30;
    meshRef.current.visible = scrollProgress > 0.7 && scrollProgress < 0.95;
    meshRef.current.rotation.x += 0.05;
    meshRef.current.rotation.y += 0.05;
  });

  const x = Math.cos(angle) * radius;
  const y = Math.sin(angle) * radius;

  return (
    <mesh ref={meshRef} position={[x, y, z]}>
      <tetrahedronGeometry args={[size, 0]} />
      <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={5} transparent opacity={0.6} />
    </mesh>
  );
};

/// <reference types="@react-three/fiber" />
import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const groupRef = useRef<THREE.Group>(null);
  const particleRef = useRef<THREE.Points>(null);
  const lightRef = useRef<THREE.PointLight>(null);

  const shapes = useMemo(() => {
    const arr = [];
    for (let i = 0; i < 40; i++) {
      const type = Math.random();
      arr.push({
        position: [
          (Math.random() - 0.5) * 45,
          (Math.random() - 0.5) * 45,
          -45 - Math.random() * 60
        ],
        rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
        scale: 0.15 + Math.random() * 1.8,
        speed: 0.01 + Math.random() * 0.05,
        geometry: type > 0.8 ? 'octahedron' : type > 0.6 ? 'icosahedron' : type > 0.4 ? 'dodecahedron' : type > 0.2 ? 'tetrahedron' : 'torusKnot',
        wireframe: Math.random() > 0.3,
        color: Math.random() > 0.6 ? '#7c3aed' : Math.random() > 0.3 ? '#4c1d95' : '#1e1b4b',
        floatSpeed: 0.2 + Math.random() * 0.3
      });
    }
    return arr;
  }, []);

  const particleCount = 2000;
  const particleData = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 100;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 100;
      pos[i * 3 + 2] = -30 - Math.random() * 100;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.82 && scrollProgress < 0.98;

    if (groupRef.current) {
      groupRef.current.visible = visible;
      groupRef.current.children.forEach((child, i) => {
        const s = shapes[i];
        if (!s) return;
        child.rotation.x += 0.0005 + (i % 10) * 0.0001;
        child.rotation.y += 0.0008 + (i % 8) * 0.0001;
        child.position.y += Math.sin(time * s.floatSpeed + i) * 0.005;
        child.position.x += Math.cos(time * s.floatSpeed * 0.8 + i) * 0.003;
      });
    }

    if (particleRef.current) {
      particleRef.current.visible = visible;
      particleRef.current.rotation.y = time * 0.01;
      particleRef.current.position.z = Math.sin(time * 0.1) * 3;
    }

    if (lightRef.current) {
      lightRef.current.visible = visible;
      lightRef.current.intensity = 15 + Math.sin(time * 0.8) * 10;
    }
  });

  return (
    <group>
      <group ref={groupRef}>
        {shapes.map((s, i) => (
          <mesh key={i} position={s.position as any} rotation={s.rotation as any} scale={s.scale}>
            {s.geometry === 'octahedron' && <octahedronGeometry args={[1, 0]} />}
            {s.geometry === 'icosahedron' && <icosahedronGeometry args={[1, 0]} />}
            {s.geometry === 'dodecahedron' && <dodecahedronGeometry args={[1, 0]} />}
            {s.geometry === 'tetrahedron' && <tetrahedronGeometry args={[1, 0]} />}
            {s.geometry === 'torusKnot' && <torusKnotGeometry args={[0.5, 0.2, 64, 8]} />}

            <meshStandardMaterial 
              color={s.color} 
              emissive={s.color} 
              emissiveIntensity={s.wireframe ? 0.6 : 0.15} 
              transparent 
              opacity={s.wireframe ? 0.4 : 0.15}
              wireframe={s.wireframe}
            />
          </mesh>
        ))}
      </group>

      <points ref={particleRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={particleCount} 
            array={particleData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.03} 
          color="#a855f7" 
          transparent 
          opacity={0.15} 
          sizeAttenuation 
        />
      </points>

      <pointLight 
        ref={lightRef}
        position={[0, 10, -50]} 
        color="#7c3aed" 
        intensity={20} 
        distance={150} 
      />

      <mesh position={[0, 0, -90]}>
        <planeGeometry args={[500, 500]} />
        <meshBasicMaterial color="#080110" transparent opacity={0.05} />
      </mesh>
    </group>
  );
};

/// <reference types="@react-three/fiber" />
import React, { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { Bloom, EffectComposer, Noise, ChromaticAberration, Vignette, Scanline } from '@react-three/postprocessing';
import { VoxelWorld } from './VoxelWorld';
import { DreamMonolith } from './DreamMonolith';
import { ParticleCore } from './ParticleCore';
import { HyperVoid } from './HyperVoid';
import { DeepVoid } from './DeepVoid';
import { CameraRig } from './CameraRig';
import { GridField } from './GridField';
import { useStore } from '../../store';

export const Scene: React.FC = () => {
  const isThinking = useStore((state) => state.isThinking);
  const scrollProgress = useStore((state) => state.scrollProgress);

  // Dynamic fog color based on level
  let fogColor = '#00050a';
  if (scrollProgress > 0.75 && scrollProgress <= 0.85) {
    fogColor = '#1a0b2e'; 
  } else if (scrollProgress > 0.85) {
    fogColor = '#0f041a'; 
  }

  return (
    <div className="fixed inset-0 w-full h-full bg-black">
      <Canvas 
        camera={{ position: [0, 0, 10], fov: 45 }}
        gl={{ antialias: false, stencil: false, depth: true, powerPreference: "high-performance" }}
      >
        <color attach="background" args={[fogColor]} />
        <fogExp2 attach="fog" args={[fogColor, 0.04]} />

        <ambientLight intensity={0.05} />
        <pointLight position={[10, 10, 10]} intensity={0.5} color="#3b82f6" />

        <Suspense fallback={null}>
          <GridField />
          <VoxelWorld />
          <DreamMonolith />
          <ParticleCore />
          <HyperVoid />
          <DeepVoid />

          <EffectComposer>
            <Bloom 
              intensity={isThinking ? 3 : 1.5} 
              luminanceThreshold={0.5} 
              luminanceSmoothing={0.9} 
            />
            <Noise opacity={0.08} />
            <Vignette eskil={false} offset={0.05} darkness={1.2} />
            <Scanline opacity={0.05} />
            {(isThinking || scrollProgress > 0.9) && (
              <ChromaticAberration offset={[0.01, 0.01] as any} />
            )}
          </EffectComposer>
        </Suspense>

        <CameraRig />
      </Canvas>
    </div>
  );
};

/// <reference types="@react-three/fiber" />
import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2000;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.5 + (Math.random() > 0.95 ? 1.5 : 0);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    meshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    if (!visibility) return;

    // Core Pulse - Slower and gentler
    const pulseSpeed = 1.5;
    const pulse = 1 + Math.sin(time * pulseSpeed) * 0.05;
    coreRef.current.scale.set(pulse, pulse, pulse);

    // Dynamic color shift
    const emissiveMaterial = coreRef.current.material as THREE.MeshPhysicalMaterial;
    const hue = (0.6 + Math.sin(time * 0.3) * 0.05) % 1; 
    emissiveMaterial.emissive.setHSL(hue, 0.8, 0.4);
    // Significant reduction in intensity pulse
    emissiveMaterial.emissiveIntensity = 2 + Math.sin(time * 2) * 0.5;

    // Energy Shell Pulse
    const shellPulse = 1.1 + Math.sin(time * 1.2) * 0.03;
    shellRef.current.scale.set(shellPulse, shellPulse, shellPulse);
    shellRef.current.rotation.y = time * 0.3;
    shellRef.current.rotation.x = time * 0.2;

    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];

      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.05;

      const offset = Math.sin(time * 0.5 + i) * 0.03;
      tempObject.position.addScalar(offset);

      const distPulse = Math.sin(time + (x+y+z)) * 0.01;
      const s = (i % 5 === 0 ? 0.08 : 0.04) * (1 - scrollProgress * 3.3) + distPulse;
      const finalScale = Math.max(0, s);
      tempObject.scale.set(finalScale, finalScale, finalScale);
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <group>
      <instancedMesh ref={meshRef} args={[undefined as any, undefined as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#3b82f6" emissive="#1e40af" emissiveIntensity={0.5} />
      </instancedMesh>

      <mesh ref={coreRef}>
        <sphereGeometry args={[2, 32, 32]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissive="#3b82f6" 
          emissiveIntensity={2} 
          transparent 
          opacity={0.8}
          roughness={0.1}
          metalness={0.9}
          transmission={0.5}
          thickness={1}
        />
      </mesh>

      <mesh ref={shellRef}>
        <icosahedronGeometry args={[2.2, 1]} />
        <meshStandardMaterial 
          color="#1e40af" 
          emissive="#3b82f6" 
          emissiveIntensity={1} 
          wireframe 
          transparent 
          opacity={0.2} 
        />
      </mesh>
    </group>
  );
};

