import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const HyperVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const gateRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Group>(null);

  const shardCount = 60;
  const shards = useMemo(() => {
    const arr = [];
    for (let i = 0; i < shardCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      const radius = 5 + Math.random() * 15;
      arr.push({
        angle,
        radius,
        speed: 0.1 + Math.random() * 0.2,
        z: -20 - Math.random() * 40,
        size: 0.2 + Math.random() * 0.5,
      });
    }
    return arr;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.72 && scrollProgress < 0.95;

    if (gateRef.current) {
      gateRef.current.visible = visible;
      gateRef.current.rotation.z = time * 0.1;
      gateRef.current.rotation.y = Math.sin(time * 0.2) * 0.05;
      gateRef.current.position.z = -30;
    }

    if (coreRef.current) {
      coreRef.current.visible = visible;
      coreRef.current.rotation.y = time * 0.5;
      coreRef.current.rotation.x = Math.sin(time * 0.3) * 0.2;
      // Soft breathing scale
      const s = 1.0 + Math.sin(time * 2) * 0.1;
      coreRef.current.scale.set(s, s, s);

      // Rotate nested parts
      const inner = coreRef.current.children[0] as THREE.Mesh;
      const outer = coreRef.current.children[1] as THREE.Mesh;
      if (inner) inner.rotation.y = -time * 1.2;
      if (outer) outer.rotation.z = time * 0.8;
    }
  });

  return (
    <group>
      <group ref={gateRef}>
        <mesh rotation={[0, 0, 0]}>
          <torusGeometry args={[12, 0.05, 8, 4]} />
          <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={2} wireframe />
        </mesh>
        <mesh rotation={[0, 0, Math.PI / 4]}>
          <torusGeometry args={[11, 0.02, 16, 100]} />
          <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={1} transparent opacity={0.3} />
        </mesh>

        {[0, 1, 2].map((i) => (
          <mesh key={i} rotation={[0, 0, (i * Math.PI) / 1.5]}>
            <boxGeometry args={[15, 0.05, 0.2]} />
            <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={0.5} transparent opacity={0.1} />
          </mesh>
        ))}
      </group>

      {/* NEW NEURAL SINGULARITY CORE */}
      <group ref={coreRef} position={[0, 0, -35]}>
        {/* Core Nucleus */}
        <mesh>
          <sphereGeometry args={[0.8, 32, 32]} />
          <meshPhysicalMaterial 
            color="#000000" 
            emissive="#ffea00" 
            emissiveIntensity={15} 
            roughness={0}
            metalness={1}
          />
        </mesh>

        {/* Tech Latice Surround */}
        <mesh>
          <dodecahedronGeometry args={[1.5, 0]} />
          <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={5} wireframe />
        </mesh>

        {/* Orbiting Shards */}
        {[0, 1, 2, 3].map((i) => (
          <group key={i} rotation={[Math.random() * Math.PI, Math.random() * Math.PI, 0]}>
            <mesh position={[2.2, 0, 0]}>
              <boxGeometry args={[0.1, 0.4, 0.4]} />
              <meshStandardMaterial color="#ffea00" emissive="#ffea00" emissiveIntensity={10} />
            </mesh>
          </group>
        ))}

        <pointLight intensity={40} color="#ffea00" distance={50} decay={2} />
      </group>

      <group position={[0, 0, -25]}>
        {shards.map((shard, i) => (
          <Shard key={i} {...shard} />
        ))}
      </group>
    </group>
  );
};

const Shard: React.FC<any> = ({ angle, radius, speed, z, size }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  useFrame((state) => {
    if (!meshRef.current) return;
    const time = state.clock.getElapsedTime();
    meshRef.current.position.z = ((z + time * speed * 50) % 60) - 30;
    meshRef.current.visible = scrollProgress > 0.7 && scrollProgress < 0.95;
    meshRef.current.rotation.x += 0.02;
    meshRef.current.rotation.y += 0.02;
  });

  const x = Math.cos(angle) * radius;
