import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

// Sophisticated Bezier-style easing
const easeInOutQuint = (t: number) => t < 0.5 ? 16 * t * t * t * t * t : 1 - Math.pow(-2 * t + 2, 5) / 2;
const easeInOutCubic = (t: number) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();
  const currentLookAt = useRef(new THREE.Vector3(0, 0, -1));

  useFrame((state, delta) => {
    // 0.00 - 0.25 : Voxel Shell
    // 0.25 - 0.50 : Manifestation
    // 0.50 - 0.75 : Sentient Core
    // 0.75 - 0.85 : HyperVoid
    // 0.85 - 1.00 : Deep Void / Infinity

    if (scrollProgress < 0.25) {
      const p = easeInOutCubic(scrollProgress / 0.25);
      targetPos.set(
        Math.cos(p * Math.PI * 0.5) * 10,
        2 + Math.sin(p * Math.PI) * 0.5,
        Math.sin(p * Math.PI * 0.5) * 10
      );
      targetLookAt.set(0, 0, 0);
    } 
    else if (scrollProgress < 0.5) {
      const p = easeInOutCubic((scrollProgress - 0.25) / 0.25);
      targetPos.lerpVectors(
        new THREE.Vector3(0, 3, 10), 
        new THREE.Vector3(0, 1, -5), 
        p
      );
      targetLookAt.set(0, 0, -10);
    } 
    else if (scrollProgress < 0.75) {
      const p = easeInOutCubic((scrollProgress - 0.5) / 0.25);
      targetPos.set(
        Math.sin(p * Math.PI * 1.5) * 4,
        Math.cos(p * Math.PI * 1.5) * 3,
        -5 - p * 15
      );
      targetLookAt.set(0, 0, -15);
    }
    else if (scrollProgress < 0.85) {
      const p = easeInOutCubic((scrollProgress - 0.75) / 0.1);
      targetPos.set(0, 0, -20 - p * 10);
      targetLookAt.set(0, 0, -35);
      camera.rotation.z = p * Math.PI * 0.1;
    }
    else {
      // Extended Void Transition (0.85 to 1.0)
      const p = easeInOutQuint((scrollProgress - 0.85) / 0.15);
      targetPos.set(
        Math.sin(p * 0.8) * 5,
        Math.cos(p * 0.8) * 5,
        -30 - p * 100
      );
      targetLookAt.set(0, 0, -150);
      camera.rotation.z = 0.1 * Math.PI + p * Math.PI * 0.3;

      if (camera instanceof THREE.PerspectiveCamera) {
        // Smoothly expand field of view as we hit terminal velocity
        camera.fov = 45 + p * 35;
        camera.updateProjectionMatrix();
      }
    }

    // Adaptive smoothing factor: heavier smoothing at high speeds
    const lerpFactor = scrollProgress > 0.85 ? 0.03 : 0.05;
    camera.position.lerp(targetPos, lerpFactor);

    // Smoothed lookAt logic
    currentLookAt.current.lerp(targetLookAt, 0.04);
    camera.lookAt(currentLookAt.current);
  });

  return null;
};

/// <reference types="@react-three/fiber" />
import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2000;
const CLOUD_COUNT = 500;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const cloudRef = useRef<THREE.Points>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.5 + (Math.random() > 0.95 ? 1.5 : 0);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  const cloudParticles = useMemo(() => {
    const pos = new Float32Array(CLOUD_COUNT * 3);
    for (let i = 0; i < CLOUD_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 4 + Math.random() * 6;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    meshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    if (cloudRef.current) cloudRef.current.visible = visibility;

    if (!visibility) return;

    // Core Pulse - Gentle
    const pulse = 1 + Math.sin(time * 1.2) * 0.04;
    coreRef.current.scale.set(pulse, pulse, pulse);

    const emissiveMaterial = coreRef.current.material as THREE.MeshPhysicalMaterial;
    emissiveMaterial.emissiveIntensity = 1.2 + Math.sin(time * 1.5) * 0.3;

    shellRef.current.rotation.y = time * 0.2;
    if (cloudRef.current) cloudRef.current.rotation.y = time * 0.05;

    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];
      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.05;
      const s = (i % 5 === 0 ? 0.06 : 0.03) * (1 - scrollProgress * 3);
      tempObject.scale.setScalar(Math.max(0, s));
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <group>
      <points ref={cloudRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CLOUD_COUNT} array={cloudParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.05} color="#3b82f6" transparent opacity={0.2} sizeAttenuation />
      </points>

      <instancedMesh ref={meshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#1e3a8a" emissive="#3b82f6" emissiveIntensity={0.2} />
      </instancedMesh>

      <mesh ref={coreRef}>
        <sphereGeometry args={[2, 32, 32]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissive="#3b82f6" 
          emissiveIntensity={1} 
          transparent 
          opacity={0.8}
          roughness={0.1}
          metalness={0.9}
        />
      </mesh>

      <mesh ref={shellRef}>
        <icosahedronGeometry args={[2.2, 1]} />
        <meshStandardMaterial color="#1e40af" emissive="#3b82f6" emissiveIntensity={0.5} wireframe transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

