  const groupRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Group>(null);
  const particleRef = useRef<THREE.Points>(null);

  const shapes = useMemo(() => {
    const arr = [];
    const geometries = ['octahedron', 'icosahedron', 'dodecahedron', 'torusKnot'];
    const colors = ['#7c3aed', '#4c1d95', '#1e1b4b', '#2e1065'];

    for (let i = 0; i < 50; i++) {
      arr.push({
        position: [(Math.random() - 0.5) * 60, (Math.random() - 0.5) * 60, -50 - Math.random() * 80],
        rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
        scale: 0.2 + Math.random() * 2.5,
        speed: 0.002 + Math.random() * 0.01,
        geometry: geometries[Math.floor(Math.random() * geometries.length)],
        wireframe: Math.random() > 0.4,
        color: colors[Math.floor(Math.random() * colors.length)],
        floatSpeed: 0.05 + Math.random() * 0.1
      });
    }
    return arr;
  }, []);

  const particleCount = 3000;
  const particleData = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 150;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 150;
      pos[i * 3 + 2] = -20 - Math.random() * 150;
    }
    return pos;
  }, []);

