        const s = shapes[i];
        if (!s) return;
        child.rotation.x += s.speed;
        child.rotation.y += s.speed * 0.5;
        child.position.y += Math.sin(time * s.floatSpeed + i) * 0.002;
      });
    }

    if (coreRef.current) {
      coreRef.current.visible = scrollProgress > 0.92;
      coreRef.current.rotation.y = time * 0.2;
      coreRef.current.children.forEach((child, i) => {
        child.rotation.x = time * (0.1 + i * 0.05);
        child.rotation.z = time * (0.05 + i * 0.02);
      });
