        <mesh rotation={[0, Math.PI/4, 0]}>
          <octahedronGeometry args={[8, 0]} />
          <meshStandardMaterial color="#1e1b4b" emissive="#4c1d95" emissiveIntensity={1} wireframe transparent opacity={0.1} />
        </mesh>
        <pointLight intensity={100} color="#a855f7" distance={200} decay={2} />
