import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

// Sophisticated Bezier-style easing functions
const easeInOutQuint = (t: number) => t < 0.5 ? 16 * t * t * t * t * t : 1 - Math.pow(-2 * t + 2, 5) / 2;
const easeInOutCubic = (t: number) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
const easeOutExpo = (t: number) => t === 1 ? 1 : 1 - Math.pow(2, -10 * t);

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();
  const currentLookAt = useRef(new THREE.Vector3(0, 0, -1));

  useFrame((state, delta) => {
    // Stage Transitions:
    // 0.00 - 0.25 : Sector 1 - Voxel Shell
    // 0.25 - 0.50 : Sector 2 - Manifestation
    // 0.50 - 0.75 : Sector 3 - Sentient Core
    // 0.75 - 0.85 : Sector 4 - HyperVoid Singularity
    // 0.85 - 1.00 : Sector 5 - Deep Void Infinity

    if (scrollProgress < 0.25) {
      const p = easeInOutCubic(scrollProgress / 0.25);
      targetPos.set(
        Math.cos(p * Math.PI * 0.5) * 10,
        2 + Math.sin(p * Math.PI) * 0.4,
        Math.sin(p * Math.PI * 0.5) * 10
      );
      targetLookAt.set(0, 0, 0);
    } 
    else if (scrollProgress < 0.5) {
      const p = easeInOutCubic((scrollProgress - 0.25) / 0.25);
      targetPos.lerpVectors(
        new THREE.Vector3(0, 3, 10), 
        new THREE.Vector3(0, 1, -5), 
        p
      );
      targetLookAt.set(0, 0, -10);
    } 
    else if (scrollProgress < 0.75) {
      const p = easeInOutCubic((scrollProgress - 0.5) / 0.25);
      targetPos.set(
        Math.sin(p * Math.PI * 1.5) * 5,
        Math.cos(p * Math.PI * 1.5) * 2,
        -5 - p * 20
      );
      targetLookAt.set(0, 0, -18);
    }
    else if (scrollProgress < 0.85) {
      const p = easeInOutCubic((scrollProgress - 0.75) / 0.1);
      targetPos.set(0, 0, -25 - p * 15);
      targetLookAt.set(0, 0, -50);
      camera.rotation.z = p * Math.PI * 0.15;
    }
    else {
      // Extended Void Transition with Expo Easing for high-speed feel
      const p = easeInOutQuint((scrollProgress - 0.85) / 0.15);
      targetPos.set(
        Math.sin(p * 1.2) * 6,
        Math.cos(p * 1.2) * 6,
        -40 - p * 130
      );
      targetLookAt.set(0, 0, -200);
      camera.rotation.z = 0.15 * Math.PI + p * Math.PI * 0.45;

      if (camera instanceof THREE.PerspectiveCamera) {
        // Expand FOV significantly at terminal depth
        camera.fov = 45 + p * 45;
        camera.updateProjectionMatrix();
      }
    }

    // Dynamic smoothing based on velocity
    const lerpFactor = scrollProgress > 0.85 ? 0.025 : 0.045;
    camera.position.lerp(targetPos, lerpFactor);

    // Smooth LookAt interpolation to prevent jarring snaps
    currentLookAt.current.lerp(targetLookAt, 0.035);
    camera.lookAt(currentLookAt.current);
  });

  return null;
};

