      const r = 1.5 + Math.random() * 1.0;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    meshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    if (cloudRef.current) cloudRef.current.visible = visibility;
    if (coreParticlesRef.current) coreParticlesRef.current.visible = visibility;
    if (coreLightRef.current) coreLightRef.current.visible = visibility;

    if (!visibility) return;

    // Gentle Core Pulse
    const pulse = 1 + Math.sin(time * 0.8) * 0.04;
