      </points>

      {/* Dense Orbiting Core Particles */}
      <points ref={coreParticlesRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CORE_PARTICLE_COUNT} array={coreParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.02} color="#93c5fd" transparent opacity={0.4} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Main Voxel Shell */}
      <instancedMesh ref={meshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#1e3a8a" emissive="#3b82f6" emissiveIntensity={0.05} />
      </instancedMesh>

      {/* Inner Core Sphere */}
      <mesh ref={coreRef}>
