const Shard: React.FC<any> = ({ angle, radius, speed, z, size }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  useFrame((state) => {
    if (!meshRef.current) return;
    const time = state.clock.getElapsedTime();
    meshRef.current.position.z = ((z + time * speed * 50) % 70) - 40;
    meshRef.current.visible = scrollProgress > 0.7 && scrollProgress < 0.95;
    meshRef.current.rotation.x += 0.02;
  });

  return (
    <mesh ref={meshRef} position={[Math.cos(angle) * radius, Math.sin(angle) * radius, z]}>
      <octahedronGeometry args={[size, 0]} />
      <meshStandardMaterial color="#facc15" emissive="#facc15" emissiveIntensity={2.5} transparent opacity={0.5} />
    </mesh>
  );
};

