import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { useStore } from '../../store';
import * as THREE from 'three';

// Cinematic easing functions
const easeInOutQuint = (t: number) => t < 0.5 ? 16 * t * t * t * t * t : 1 - Math.pow(-2 * t + 2, 5) / 2;
const easeInOutCubic = (t: number) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
const easeInOutSine = (t: number) => -(Math.cos(Math.PI * t) - 1) / 2;

export const CameraRig: React.FC = () => {
  const { camera } = useThree();
  const scrollProgress = useStore((state) => state.scrollProgress);

  const targetPos = new THREE.Vector3();
  const targetLookAt = new THREE.Vector3();
  const currentLookAt = useRef(new THREE.Vector3(0, 0, -1));

  useFrame((state, delta) => {
    // Stage Transitions:
    // 0.00 - 0.25 : Sector 1 - Voxel Shell
    // 0.25 - 0.50 : Sector 2 - Manifestation (Monolith)
    // 0.50 - 0.75 : Sector 3 - Sentient Core
    // 0.75 - 0.85 : Sector 4 - HyperVoid Singularity
    // 0.85 - 1.00 : Sector 5 - Deep Void Infinity

    if (scrollProgress < 0.25) {
      // Smooth orbital movement in Level 1
      const p = easeInOutSine(scrollProgress / 0.25);
      targetPos.set(
        Math.cos(p * Math.PI * 0.5) * 12,
        2 + Math.sin(p * Math.PI) * 0.5,
        Math.sin(p * Math.PI * 0.5) * 12
      );
      targetLookAt.set(0, 0, 0);
    } 
    else if (scrollProgress < 0.5) {
      // REFINED TRANSITION into Level 2
      const p = easeInOutCubic((scrollProgress - 0.25) / 0.25);
      const startPos = new THREE.Vector3(0, 2.5, 12); // Where Sector 1 ends
      const endPos = new THREE.Vector3(0, 1.2, -4);  // Ideal focus for Monolith

      targetPos.lerpVectors(startPos, endPos, p);
      // Fluidly shift focus from center to Monolith
      targetLookAt.lerpVectors(new THREE.Vector3(0, 0, 0), new THREE.Vector3(0, 0, -8), p);
    } 
    else if (scrollProgress < 0.75) {
      const p = easeInOutCubic((scrollProgress - 0.5) / 0.25);
      targetPos.set(
        Math.sin(p * Math.PI * 1.5) * 6,
        Math.cos(p * Math.PI * 1.5) * 3,
        -5 - p * 25
      );
      targetLookAt.set(0, 0, -20);
    }
    else if (scrollProgress < 0.85) {
      const p = easeInOutCubic((scrollProgress - 0.75) / 0.1);
      targetPos.set(0, 0, -30 - p * 20);
      targetLookAt.set(0, 0, -60);
      camera.rotation.z = p * Math.PI * 0.12;
    }
    else {
      // High-speed plunge into Infinity
      const p = easeInOutQuint((scrollProgress - 0.85) / 0.15);
      targetPos.set(
        Math.sin(p * 1.5) * 8,
        Math.cos(p * 1.5) * 8,
        -50 - p * 150
      );
      targetLookAt.set(0, 0, -250);
      camera.rotation.z = 0.12 * Math.PI + p * Math.PI * 0.5;

      if (camera instanceof THREE.PerspectiveCamera) {
        camera.fov = 45 + p * 50;
        camera.updateProjectionMatrix();
      }
    }

    // Dynamic smoothing - lower factor at extreme depths for responsiveness
    const lerpFactor = scrollProgress > 0.85 ? 0.03 : 0.045;
    camera.position.lerp(targetPos, lerpFactor);

    // Smooth target lookAt
    currentLookAt.current.lerp(targetLookAt, 0.04);
    camera.lookAt(currentLookAt.current);
  });

  return null;
};

