  const groupRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Group>(null);
  const dustRef = useRef<THREE.Points>(null);
  const starsRef = useRef<THREE.Points>(null);

  const shapes = useMemo(() => {
    const arr = [];
    const geometries = ['octahedron', 'icosahedron', 'dodecahedron', 'torusKnot', 'tetrahedron', 'cone', 'cylinder'];
    const colors = ['#5b21b6', '#4c1d95', '#1e1b4b', '#2e1065', '#0f172a', '#1e105a'];

    for (let i = 0; i < 75; i++) {
      arr.push({
        position: [(Math.random() - 0.5) * 120, (Math.random() - 0.5) * 120, -70 - Math.random() * 140],
        rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
        scale: 0.3 + Math.random() * 4.0,
        speed: 0.001 + Math.random() * 0.01,
        geometry: geometries[Math.floor(Math.random() * geometries.length)],
        wireframe: Math.random() > 0.4,
        color: colors[Math.floor(Math.random() * colors.length)],
        floatSpeed: 0.04 + Math.random() * 0.08
      });
    }
    return arr;
  }, []);

  const starData = useMemo(() => {
    const pos = new Float32Array(STAR_COUNT * 3);
    for (let i = 0; i < STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 300 + Math.random() * 200;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi) - 200;
    }
    return pos;
  }, []);

  const dustData = useMemo(() => {
    const pos = new Float32Array(DUST_COUNT * 3);
    for (let i = 0; i < DUST_COUNT; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 400;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 400;
      pos[i * 3 + 2] = -60 - Math.random() * 400;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.8;

    if (groupRef.current) {
      groupRef.current.visible = visible;
      groupRef.current.children.forEach((child, i) => {
        const s = shapes[i];
