    if (coreRef.current) {
      coreRef.current.visible = scrollProgress > 0.92;
      coreRef.current.rotation.y = time * 0.08;
    }

    if (starsRef.current) {
      starsRef.current.visible = visible;
      starsRef.current.rotation.y = time * 0.0003;
    }

    if (dustRef.current) {
      dustRef.current.visible = visible;
      dustRef.current.position.z = Math.sin(time * 0.008) * 10;
    }
  });

  return (
    <group>
