      <points ref={starsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={STAR_COUNT} array={starData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.18} color="#ffffff" transparent opacity={0.6} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Floating Neural Core - Final Singularity */}
      <group ref={coreRef} position={[0, 0, -180]}>
        <mesh>
          <icosahedronGeometry args={[8, 2]} />
          <meshStandardMaterial color="#7c3aed" emissive="#a855f7" emissiveIntensity={3} wireframe transparent opacity={0.5} />
        </mesh>
        <mesh rotation={[Math.PI/2, 0, 0]}>
          <torusKnotGeometry args={[14, 0.2, 128, 16]} />
          <meshStandardMaterial color="#4c1d95" emissive="#7c3aed" emissiveIntensity={1.5} wireframe transparent opacity={0.25} />
        </mesh>
        <pointLight intensity={150} color="#a855f7" distance={400} decay={2} />
      </group>

      {/* Complex Geometric Shapes */}
      <group ref={groupRef}>
        {shapes.map((s, i) => (
          <mesh key={i} position={s.position as any} rotation={s.rotation as any} scale={s.scale}>
            {s.geometry === 'octahedron' && <octahedronGeometry args={[1, 0]} />}
            {s.geometry === 'icosahedron' && <icosahedronGeometry args={[1, 0]} />}
            {s.geometry === 'dodecahedron' && <dodecahedronGeometry args={[1, 0]} />}
            {s.geometry === 'tetrahedron' && <tetrahedronGeometry args={[1, 0]} />}
            {s.geometry === 'torusKnot' && <torusKnotGeometry args={[0.5, 0.1, 80, 12]} />}
            {s.geometry === 'cone' && <coneGeometry args={[0.7, 1.5, 32]} />}
            {s.geometry === 'cylinder' && <cylinderGeometry args={[0.5, 0.5, 1.5, 32]} />}

            <meshStandardMaterial 
              color={s.color} 
              emissive={s.color} 
              emissiveIntensity={s.wireframe ? 0.35 : 0.05} 
              transparent 
              opacity={s.wireframe ? 0.3 : 0.15} 
              wireframe={s.wireframe} 
            />
          </mesh>
        ))}
      </group>

      {/* Nebular Dust Particles */}
      <points ref={dustRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={DUST_COUNT} array={dustData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.035} color="#7c3aed" transparent opacity={0.18} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Infinite Void Plane */}
      <mesh position={[0, 0, -300]}>
        <planeGeometry args={[10000, 10000]} />
        <meshBasicMaterial color="#010001" />
      </mesh>
    </group>
  );
};

