        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={COSMO_STAR_COUNT} array={cosmoStarData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={COSMO_STAR_COUNT} array={cosmoStarData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.6} 
          vertexColors 
          transparent 
          opacity={0.8} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* Final Singularity Core */}
      <group ref={coreRef} position={[0, 0, -200]}>
        <mesh>
          <icosahedronGeometry args={[10, 2]} />
          <meshStandardMaterial color="#7c3aed" emissive="#a855f7" emissiveIntensity={3} wireframe transparent opacity={0.5} />
