/// <reference types="@react-three/fiber" />
import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2000;
const CLOUD_COUNT = 2500;
const CORE_PARTICLE_COUNT = 3000;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const coreParticlesRef = useRef<THREE.Points>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const cloudRef = useRef<THREE.Points>(null);
  const coreLightRef = useRef<THREE.PointLight>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.5 + (Math.random() > 0.9 ? 1.2 : 0);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  const cloudParticles = useMemo(() => {
    const pos = new Float32Array(CLOUD_COUNT * 3);
    for (let i = 0; i < CLOUD_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 4 + Math.random() * 12;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  const coreParticles = useMemo(() => {
    const pos = new Float32Array(CORE_PARTICLE_COUNT * 3);
    for (let i = 0; i < CORE_PARTICLE_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 1.2 + Math.random() * 1.5;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    meshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    if (cloudRef.current) cloudRef.current.visible = visibility;
    if (coreParticlesRef.current) coreParticlesRef.current.visible = visibility;
    if (coreLightRef.current) coreLightRef.current.visible = visibility;

    if (!visibility) return;

    const pulse = 1 + Math.sin(time * 0.8) * 0.04;
    coreRef.current.scale.setScalar(pulse);

    const emissiveMaterial = coreRef.current.material as THREE.MeshPhysicalMaterial;
    emissiveMaterial.emissiveIntensity = 2.0 + Math.sin(time * 1.5) * 0.5;
    emissiveMaterial.emissive.setRGB(0.3, 0.5 + Math.sin(time * 1.5) * 0.2, 1.0);

    if (coreLightRef.current) {
      coreLightRef.current.intensity = 35 + Math.sin(time * 2) * 12;
      coreLightRef.current.color.setRGB(0.3, 0.5 + Math.sin(time * 1.5) * 0.2, 1.0);
    }

    shellRef.current.rotation.y = time * 0.1;
    if (cloudRef.current) {
      cloudRef.current.rotation.y = time * 0.015;
    }
    if (coreParticlesRef.current) {
      coreParticlesRef.current.rotation.y = -time * 0.45;
      coreParticlesRef.current.rotation.z = time * 0.25;
    }

    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];
      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.05;
      const s = (i % 5 === 0 ? 0.04 : 0.015) * (1 - scrollProgress * 3);
      tempObject.scale.setScalar(Math.max(0, s));
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <group>
      <pointLight ref={coreLightRef} intensity={30} distance={18} decay={2} />

      <points ref={cloudRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CLOUD_COUNT} array={cloudParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.02} color="#3b82f6" transparent opacity={0.15} sizeAttenuation />
      </points>

      <points ref={coreParticlesRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CORE_PARTICLE_COUNT} array={coreParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.024} 
          color="#93c5fd" 
          transparent 
          opacity={0.65} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      <instancedMesh ref={meshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#1e3a8a" emissive="#3b82f6" emissiveIntensity={0.05} />
      </instancedMesh>

      <mesh ref={coreRef}>
        <sphereGeometry args={[2, 32, 32]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissiveIntensity={2.0} 
          transparent 
          opacity={0.9}
          roughness={0.1}
          metalness={0.9}
        />
      </mesh>

      <mesh ref={shellRef}>
        <icosahedronGeometry args={[2.35, 1]} />
        <meshStandardMaterial color="#1e40af" emissive="#3b82f6" emissiveIntensity={0.4} wireframe transparent opacity={0.15} />
      </mesh>
    </group>
  );
};

/// <reference types="@react-three/fiber" />
import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2400; // Denser shell
const CLOUD_COUNT = 3000;
