import React, { useRef } from 'react';
import { useFrame, useLoader } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const DreamMonolith: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null);
  const ring1Ref = useRef<THREE.Mesh>(null);
  const ring2Ref = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const dreamTextureUrl = useStore((state) => state.dreamTextureUrl);

  const texture = dreamTextureUrl ? useLoader(THREE.TextureLoader, dreamTextureUrl) : null;

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress >= 0.22 && scrollProgress <= 0.55;

    if (meshRef.current) {
      meshRef.current.position.y = Math.sin(time * 0.5) * 0.2;
      meshRef.current.rotation.y = time * 0.1;
      meshRef.current.visible = visible;
      const s = THREE.MathUtils.smoothstep(scrollProgress, 0.22, 0.4) * 1.5;
      meshRef.current.scale.set(s, s * 2, s);
    }

    if (ring1Ref.current && ring2Ref.current) {
      ring1Ref.current.visible = visible;
      ring2Ref.current.visible = visible;
      ring1Ref.current.rotation.x = time * 0.4;
      ring1Ref.current.rotation.y = time * 0.2;
      ring2Ref.current.rotation.z = time * -0.3;
      ring2Ref.current.rotation.x = time * 0.15;

      const rs = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.4) * 4;
      ring1Ref.current.scale.set(rs, rs, rs);
      ring2Ref.current.scale.set(rs * 1.2, rs * 1.2, rs * 1.2);
    }
  });

  return (
    <group position={[0, 0, -5]}>
      <mesh ref={meshRef}>
        <boxGeometry args={[1, 2, 0.1]} />
        <meshStandardMaterial 
          map={texture || undefined} 
          color={texture ? "#ffffff" : "#050505"}
          metalness={1}
          roughness={0}
          emissive={texture ? "#ffffff" : "#1e3a8a"}
          emissiveIntensity={texture ? 0.8 : 0.2}
        />
        <pointLight intensity={10} color="#3b82f6" distance={10} />
      </mesh>

      <mesh ref={ring1Ref}>
        <torusGeometry args={[1, 0.01, 16, 100]} />
        <meshStandardMaterial color="#3b82f6" emissive="#3b82f6" emissiveIntensity={10} transparent opacity={0.5} />
      </mesh>

      <mesh ref={ring2Ref}>
        <torusGeometry args={[1, 0.005, 16, 100]} />
        <meshStandardMaterial color="#60a5fa" emissive="#60a5fa" emissiveIntensity={10} transparent opacity={0.3} />
      </mesh>
    </group>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const ParticleCore: React.FC = () => {
  const pointsRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const isThinking = useStore((state) => state.isThinking);

  const particleCount = 3000;
  const positions = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      const r = 2.5 + Math.random() * 6.5;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const jitter = 1.0 + (Math.random() - 0.5) * 0.3;

      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta) * jitter;
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta) * jitter;
      pos[i * 3 + 2] = r * Math.cos(phi) * jitter;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.45 && scrollProgress < 0.85;

    if (pointsRef.current) {
      pointsRef.current.rotation.y = time * 0.06;
      pointsRef.current.visible = visible;

      if (isThinking) {
        // Erratic particle vibration
        pointsRef.current.position.x = (Math.random() - 0.5) * 0.12;
        pointsRef.current.position.y = (Math.random() - 0.5) * 0.12;
        pointsRef.current.scale.setScalar(1 + Math.sin(time * 35) * 0.05);
      } else {
        pointsRef.current.position.x = 0;
        pointsRef.current.position.y = 0;
        pointsRef.current.scale.setScalar(1 + Math.sin(time * 0.8) * 0.02);
      }
    }

    if (coreRef.current) {
      coreRef.current.visible = scrollProgress > 0.52 && scrollProgress < 0.82;
      coreRef.current.rotation.x = time * 0.5;
      coreRef.current.rotation.y = time * 0.8;

      // Dynamic scaling logic
      let scale = 1.0;
      if (isThinking) {
        // Sharp, erratic pulses for thinking state
        scale = 1.2 + Math.sin(time * 50) * 0.25;
        const mat = coreRef.current.material as THREE.MeshStandardMaterial;
        mat.emissiveIntensity = 15 + Math.random() * 20;
      } else {
        // Smooth, breathing pulse for idle state
        const breathing = 1 + Math.sin(time * 2.5) * 0.15;
        // Scale based on scroll entrance
        const entrance = THREE.MathUtils.smoothstep(scrollProgress, 0.5, 0.6);
        scale = breathing * entrance * 1.2;
        const mat = coreRef.current.material as THREE.MeshStandardMaterial;
        mat.emissiveIntensity = 8 + Math.sin(time * 2) * 4;
      }
      coreRef.current.scale.setScalar(scale);
    }
  });

  return (
    <group position={[0, 0, -15]}>
      <points ref={pointsRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={particleCount} 
            array={positions} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.05} 
          color="#facc15" 
          transparent 
          opacity={0.6} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending}
        />
      </points>

      <mesh ref={coreRef}>
        <octahedronGeometry args={[1.2, 0]} />
        <meshStandardMaterial 
          color="#fef08a" 
          emissive="#facc15" 
          emissiveIntensity={10} 
          wireframe 
          transparent
          opacity={0.9}
        />
        <pointLight intensity={40} color="#facc15" distance={18} decay={2} />
      </mesh>
    </group>
  );
};

