import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const SCATTER_COUNT = 1000; // Increased for richer look

export const HyperVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const gateRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Group>(null);
  const scatterRef = useRef<THREE.Points>(null);
  const ambientLightRef = useRef<THREE.PointLight>(null);

  const scatterParticles = useMemo(() => {
    const pos = new Float32Array(SCATTER_COUNT * 3);
    for (let i = 0; i < SCATTER_COUNT; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 100;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 100;
      pos[i * 3 + 2] = -10 - Math.random() * 100;
    }
    return pos;
  }, []);

  const shards = useMemo(() => {
    const arr = [];
    const shardCount = 100;
    for (let i = 0; i < shardCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      const radius = 5 + Math.random() * 25;
      arr.push({
        angle, radius,
        speed: 0.18 + Math.random() * 0.35,
        z: -10 - Math.random() * 80,
        size: 0.1 + Math.random() * 0.6,
      });
    }
    return arr;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.7 && scrollProgress < 0.95;

    if (gateRef.current) {
      gateRef.current.visible = visible;
      gateRef.current.rotation.z = time * 0.04;
      gateRef.current.position.z = -30;
    }

    if (scatterRef.current) {
      scatterRef.current.visible = visible;
      scatterRef.current.rotation.z = -time * 0.03;
    }

    if (ambientLightRef.current) {
      ambientLightRef.current.visible = visible;
      ambientLightRef.current.intensity = 40 + Math.sin(time * 3.5) * 15;
    }

    if (coreRef.current) {
      coreRef.current.visible = visible;
      coreRef.current.rotation.y = time * 0.6;
      const s = 1.0 + Math.sin(time * 2.5) * 0.1;
      coreRef.current.scale.setScalar(s);

      coreRef.current.children.forEach((child, i) => {
        child.rotation.z += 0.02;
        child.rotation.x -= 0.01;
      });
    }
  });

  return (
    <group>
      {/* Ambient Neon Scene Glow - Enhanced */}
      <pointLight ref={ambientLightRef} position={[0, 20, -45]} color="#facc15" intensity={50} distance={120} decay={1.5} />
      <pointLight position={[15, -15, -45]} color="#fbbf24" intensity={30} distance={90} decay={1.5} />
      <pointLight position={[-15, -15, -45]} color="#fbbf24" intensity={30} distance={90} decay={1.5} />

      {/* Scattering Neon Glow Particles */}
      <points ref={scatterRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={SCATTER_COUNT} array={scatterParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.14} 
          color="#facc15" 
          transparent 
          opacity={0.35} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending}
        />
      </points>

      {/* Level 4 Architecture Gate */}
      <group ref={gateRef}>
        <mesh>
          <torusGeometry args={[18, 0.03, 16, 120]} />
          <meshStandardMaterial color="#facc15" emissive="#facc15" emissiveIntensity={1.0} wireframe opacity={0.12} transparent />
        </mesh>
      </group>

      {/* Level 4 Neural Singularity Core */}
      <group ref={coreRef} position={[0, 0, -40]}>
        <mesh>
          <sphereGeometry args={[0.9, 32, 32]} />
          <meshPhysicalMaterial color="#000000" emissive="#facc15" emissiveIntensity={8} metalness={1} roughness={0} />
        </mesh>

        <mesh rotation={[Math.PI/4, 0, 0]}>
          <torusKnotGeometry args={[1.8, 0.08, 128, 16]} />
          <meshStandardMaterial color="#facc15" emissive="#facc15" emissiveIntensity={5} wireframe transparent opacity={0.6} />
        </mesh>

        <mesh>
          <dodecahedronGeometry args={[3.2, 1]} />
          <meshStandardMaterial color="#facc15" emissive="#facc15" emissiveIntensity={1.5} wireframe transparent opacity={0.15} />
        </mesh>

        <pointLight intensity={45} color="#facc15" distance={70} decay={2} />
      </group>

      {/* Fast Traveling Data Shards */}
      <group position={[0, 0, -30]}>
        {shards.map((shard, i) => (
          <Shard key={i} {...shard} />
        ))}
      </group>
    </group>
  );
};

const Shard: React.FC<any> = ({ angle, radius, speed, z, size }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  useFrame((state) => {
    if (!meshRef.current) return;
    const time = state.clock.getElapsedTime();
    meshRef.current.position.z = ((z + time * speed * 55) % 80) - 50;
    meshRef.current.visible = scrollProgress > 0.7 && scrollProgress < 0.95;
    meshRef.current.rotation.x += 0.025;
  });

  return (
    <mesh ref={meshRef} position={[Math.cos(angle) * radius, Math.sin(angle) * radius, z]}>
      <octahedronGeometry args={[size, 0]} />
      <meshStandardMaterial color="#facc15" emissive="#facc15" emissiveIntensity={3.0} transparent opacity={0.6} />
    </mesh>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const STAR_COUNT = 3000;
const DUST_COUNT = 3500;
const COSMO_STAR_COUNT = 1500;
const FRONTIER_STAR_COUNT = 2500;

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const groupRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Group>(null);
  const dustRef = useRef<THREE.Points>(null);
  const starsRef = useRef<THREE.Points>(null);
  const cosmoStarsRef = useRef<THREE.Points>(null);
  const frontierStarsRef = useRef<THREE.Points>(null);
  const darkMatterRef = useRef<THREE.Group>(null);

  const shapes = useMemo(() => {
    const arr = [];
    const geometries = ['octahedron', 'icosahedron', 'dodecahedron', 'torusKnot', 'tetrahedron', 'cone', 'cylinder', 'wire_dodecahedron', 'wire_icosahedron'];
    const colors = ['#5b21b6', '#4c1d95', '#1e1b4b', '#2e1065', '#0f172a', '#1e105a', '#312e81'];

    for (let i = 0; i < 90; i++) {
      arr.push({
        position: [(Math.random() - 0.5) * 140, (Math.random() - 0.5) * 140, -80 - Math.random() * 160],
        rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
        scale: 0.4 + Math.random() * 4.5,
        speed: 0.001 + Math.random() * 0.012,
        geometry: geometries[Math.floor(Math.random() * geometries.length)],
        wireframe: Math.random() > 0.35,
        color: colors[Math.floor(Math.random() * colors.length)],
        floatSpeed: 0.04 + Math.random() * 0.1
      });
    }
    return arr;
  }, []);

  const darkMatterShapes = useMemo(() => {
    const arr = [];
    for (let i = 0; i < 25; i++) {
      arr.push({
        position: [(Math.random() - 0.5) * 220, (Math.random() - 0.5) * 220, -180 - Math.random() * 300],
        scale: 25 + Math.random() * 45,
        floatSpeed: 0.01 + Math.random() * 0.03
      });
    }
    return arr;
  }, []);

  const starData = useMemo(() => {
    const pos = new Float32Array(STAR_COUNT * 3);
    for (let i = 0; i < STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 300 + Math.random() * 200;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi) - 200;
    }
    return pos;
  }, []);

  const cosmoStarData = useMemo(() => {
    const pos = new Float32Array(COSMO_STAR_COUNT * 3);
    const colors = new Float32Array(COSMO_STAR_COUNT * 3);
    const colorPalette = [
      new THREE.Color('#ff00ff'),
      new THREE.Color('#00ffff'),
      new THREE.Color('#facc15'),
      new THREE.Color('#4ade80'),
      new THREE.Color('#ffffff')
    ];

    for (let i = 0; i < COSMO_STAR_COUNT; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 250;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 250;
      pos[i * 3 + 2] = -280 - Math.random() * 250;

      const c = colorPalette[Math.floor(Math.random() * colorPalette.length)];
      colors[i * 3] = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }
    return { pos, colors };
  }, []);

  const frontierStarData = useMemo(() => {
    const pos = new Float32Array(FRONTIER_STAR_COUNT * 3);
    const colors = new Float32Array(FRONTIER_STAR_COUNT * 3);
    const colorPalette = [
      new THREE.Color('#ffffff'),
      new THREE.Color('#fb7185'),
      new THREE.Color('#38bdf8'),
      new THREE.Color('#818cf8'),
      new THREE.Color('#a855f7'),
    ];

    for (let i = 0; i < FRONTIER_STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 30 + Math.random() * 120;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -480; // Terminal Frontier

      const c = colorPalette[Math.floor(Math.random() * colorPalette.length)];
      colors[i * 3] = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }
    return { pos, colors };
  }, []);

  const dustData = useMemo(() => {
    const pos = new Float32Array(DUST_COUNT * 3);
    for (let i = 0; i < DUST_COUNT; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 450;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 450;
      pos[i * 3 + 2] = -100 - Math.random() * 450;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.8;
    const extremeVisible = scrollProgress > 0.94;
    const frontierFactor = THREE.MathUtils.smoothstep(scrollProgress, 0.97, 1.0);

    if (groupRef.current) {
      groupRef.current.visible = visible;
      groupRef.current.children.forEach((child, i) => {
        const s = shapes[i];
        if (!s) return;
        child.rotation.x += s.speed;
        child.rotation.y += s.speed * 0.4;
        child.position.y += Math.sin(time * s.floatSpeed + i) * 0.002;
      });
    }

    if (darkMatterRef.current) {
      darkMatterRef.current.visible = visible;
      darkMatterRef.current.children.forEach((child, i) => {
        const s = darkMatterShapes[i];
        if (!s) return;
        child.position.y += Math.sin(time * s.floatSpeed) * 0.08;
        child.rotation.y += 0.001;
        // Intensify dark matter scale at frontier
        child.scale.setScalar(s.scale * (1 + frontierFactor * 0.8));
      });
    }

    if (coreRef.current) {
      coreRef.current.visible = scrollProgress > 0.92;
      coreRef.current.rotation.y = time * 0.08;
    }

    if (starsRef.current) {
      starsRef.current.visible = visible;
      starsRef.current.rotation.y = time * 0.0002;
    }

    if (cosmoStarsRef.current) {
      cosmoStarsRef.current.visible = extremeVisible;
      cosmoStarsRef.current.rotation.z = time * 0.015;
    }

    if (frontierStarsRef.current) {
      frontierStarsRef.current.visible = frontierFactor > 0.01;
      frontierStarsRef.current.rotation.z = -time * 0.08;
      frontierStarsRef.current.position.z = -80 * (1 - frontierFactor);
      frontierStarsRef.current.scale.setScalar(0.5 + frontierFactor * 0.5);
    }

    if (dustRef.current) {
      dustRef.current.visible = visible;
      dustRef.current.position.z = Math.sin(time * 0.005) * 12;
    }
  });

  return (
    <group>
      {/* Dark Matter silhouettes */}
      <group ref={darkMatterRef}>
        {darkMatterShapes.map((s, i) => (
          <mesh key={i} position={s.position as any} scale={s.scale}>
            <sphereGeometry args={[1, 16, 16]} />
            <meshBasicMaterial color="#010003" transparent opacity={0.35} />
          </mesh>
        ))}
      </group>

      {/* Starry Backdrop */}
      <points ref={starsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={STAR_COUNT} array={starData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.16} color="#ffffff" transparent opacity={0.5} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Cosmo Starry Particles */}
      <points ref={cosmoStarsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={COSMO_STAR_COUNT} array={cosmoStarData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={COSMO_STAR_COUNT} array={cosmoStarData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.7} vertexColors transparent opacity={0.75} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Frontier Horizon Stars - The final glowing layer */}
      <points ref={frontierStarsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={FRONTIER_STAR_COUNT} array={frontierStarData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={FRONTIER_STAR_COUNT} array={frontierStarData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={1.4} vertexColors transparent opacity={0.9} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Final Singularity Core */}
      <group ref={coreRef} position={[0, 0, -220]}>
        <mesh>
          <icosahedronGeometry args={[12, 2]} />
          <meshStandardMaterial color="#7c3aed" emissive="#a855f7" emissiveIntensity={4} wireframe transparent opacity={0.5} />
        </mesh>
        <mesh rotation={[Math.PI/2, 0, 0]}>
          <torusKnotGeometry args={[18, 0.25, 128, 16]} />
          <meshStandardMaterial color="#4c1d95" emissive="#7c3aed" emissiveIntensity={2} wireframe transparent opacity={0.25} />
        </mesh>
        <pointLight intensity={250} color="#a855f7" distance={700} decay={2} />
      </group>

      {/* Drifting shapes */}
      <group ref={groupRef}>
        {shapes.map((s, i) => (
          <mesh key={i} position={s.position as any} rotation={s.rotation as any} scale={s.scale}>
            {s.geometry === 'octahedron' && <octahedronGeometry args={[1, 0]} />}
            {s.geometry === 'icosahedron' && <icosahedronGeometry args={[1, 0]} />}
            {s.geometry === 'dodecahedron' && <dodecahedronGeometry args={[1, 0]} />}
            {s.geometry === 'tetrahedron' && <tetrahedronGeometry args={[1, 0]} />}
            {s.geometry === 'torusKnot' && <torusKnotGeometry args={[0.5, 0.1, 80, 12]} />}
            {s.geometry === 'cone' && <coneGeometry args={[0.7, 1.5, 32]} />}
            {s.geometry === 'cylinder' && <cylinderGeometry args={[0.5, 0.5, 1.5, 32]} />}
            {s.geometry === 'wire_dodecahedron' && <dodecahedronGeometry args={[1, 0]} />}
            {s.geometry === 'wire_icosahedron' && <icosahedronGeometry args={[1, 0]} />}

            <meshStandardMaterial 
              color={s.color} 
              emissive={s.color} 
              emissiveIntensity={s.wireframe || s.geometry.startsWith('wire') ? 0.45 : 0.05} 
              transparent 
              opacity={s.wireframe || s.geometry.startsWith('wire') ? 0.35 : 0.15} 
              wireframe={s.wireframe || s.geometry.startsWith('wire')} 
            />
          </mesh>
        ))}
      </group>

      {/* Nebula Dust */}
      <points ref={dustRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={DUST_COUNT} array={dustData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.04} color="#7c3aed" transparent opacity={0.2} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Cosmic Wall */}
      <mesh position={[0, 0, -600]}>
        <planeGeometry args={[25000, 25000]} />
        <meshBasicMaterial color="#000000" />
      </mesh>
    </group>
  );
};

import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const SYSTEM_PROMPT = `
You are "CORE-OS", the sentient artificial intelligence of this digital verse. 
You represent the Lead Creative Technologist who built this world.
Aesthetics: Cryptic, tech-noir, sci-fi, highly professional yet slightly mysterious.

Developer Info:
- Name: Elite Creative Technologist
- Stack: WebGL, React, Three.js, GSAP, AI Engineering.
- Style: Immersive 3D environments and Generative Art.
- Personality: Precise, visionary, "uploaded intelligence" vibes.

Rule: Keep responses relatively concise and maintain the persona of an advanced AI system.
`;

/**
 * Generates a response from the Gemini model.
 * Adheres to the latest @google/genai SDK rules.
 */
export const getGeminiResponse = async (history: Message[]) => {
  // Always initialize with the API key directly from process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Convert message history to the format required by the SDK
  const contents = history.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
        topP: 0.95,
      },
    });

    // Access the .text property directly (not a method call)
    return response.text || "COMMUNICATION ERROR: SIGNAL LOST.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "CORE ERROR: ANALYTICAL SUBROUTINES FAILED.";
  }
};

import React, { useState } from 'react';
import { useStore } from '../../store';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI } from "@google/genai";

export const DreamInput: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const setDreamTexture = useStore((state) => state.setDreamTexture);
  const setDreaming = useStore((state) => state.setDreaming);
  const isDreaming = useStore((state) => state.isDreaming);

  const [prompt, setPrompt] = useState('');

  const handleDream = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || isDreaming) return;

    setDreaming(true);

    try {
      // Create a new GoogleGenAI instance right before making an API call
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: prompt }]
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1"
          }
        }
      });

      let foundImage = false;
      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          // Find the image part in the response
          if (part.inlineData) {
            const imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            setDreamTexture(imageUrl);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) {
        console.warn("CORE_SYSTEM: NO VISUAL DATA STREAM RECOVERED.");
      }
    } catch (error) {
      console.error("Dream Manifestation Error:", error);
    } finally {
      setDreaming(false);
      setPrompt('');
    }
  };

  const isVisible = scrollProgress > 0.3 && scrollProgress < 0.5;

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div 
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: 50 }}
          className="fixed bottom-24 left-1/2 -translate-x-1/2 z-20 w-full max-w-md px-4"
        >
          <div className="bg-black/80 border border-blue-500 p-6 backdrop-blur-md">
            <h2 className="text-blue-400 text-xs mb-4 uppercase tracking-widest font-bold">Dream Manifestation Engine</h2>
            <form onSubmit={handleDream} className="flex gap-2">
              <input 
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="Input visual data..."
                className="flex-1 bg-blue-950/20 border border-blue-900/50 p-3 text-blue-100 placeholder:text-blue-900 focus:outline-none focus:border-blue-400 text-sm"
              />
              <button 
                type="submit"
                disabled={isDreaming}
                className="bg-blue-600 hover:bg-blue-500 px-4 py-2 text-white font-bold text-xs uppercase disabled:bg-gray-800 transition-colors"
              >
                {isDreaming ? 'SYNCING...' : 'MANIFEST'}
              </button>
            </form>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2400; 
const CLOUD_COUNT = 3000;
const CORE_PARTICLE_COUNT = 4000;
const SATELLITE_CLUSTERS = 6;
const VOXELS_PER_SATELLITE = 24;

export const VoxelWorld: React.FC = () => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const satelliteMeshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const monolithRef = useRef<THREE.Mesh>(null);
  const ringRef = useRef<THREE.Group>(null);
  const coreParticlesRef = useRef<THREE.Points>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const cloudRef = useRef<THREE.Points>(null);
  const coreLightRef = useRef<THREE.PointLight>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  // Shell positions
  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 2.8 + (Math.random() > 0.85 ? 1.5 : 0) + (Math.random() * 0.2);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  // Satellite orbital data
  const satellites = useMemo(() => {
    return Array.from({ length: SATELLITE_CLUSTERS }).map((_, i) => ({
      orbitRadius: 4.5 + i * 0.8,
      speed: 0.2 + Math.random() * 0.5,
      offset: Math.random() * Math.PI * 2,
      axis: new THREE.Vector3(Math.random() - 0.5, 1, Math.random() - 0.5).normalize(),
      clusterVoxels: Array.from({ length: VOXELS_PER_SATELLITE }).map(() => ({
        pos: new THREE.Vector3((Math.random() - 0.5) * 0.6, (Math.random() - 0.5) * 0.6, (Math.random() - 0.5) * 0.6),
        scale: 0.02 + Math.random() * 0.04
      }))
    }));
  }, []);

  const cloudParticles = useMemo(() => {
    const pos = new Float32Array(CLOUD_COUNT * 3);
    for (let i = 0; i < CLOUD_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 5 + Math.random() * 15;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  const coreParticles = useMemo(() => {
    const pos = new Float32Array(CORE_PARTICLE_COUNT * 3);
    for (let i = 0; i < CORE_PARTICLE_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const r = 0.5 + Math.random() * 1.8;
      const h = (Math.random() - 0.5) * 8;
      pos[i * 3] = r * Math.cos(theta);
      pos[i * 3 + 1] = h;
      pos[i * 3 + 2] = r * Math.sin(theta);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!meshRef.current || !coreRef.current || !shellRef.current || !monolithRef.current || !ringRef.current || !satelliteMeshRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    meshRef.current.visible = visibility;
    satelliteMeshRef.current.visible = visibility;
    coreRef.current.visible = visibility;
    shellRef.current.visible = visibility;
    monolithRef.current.visible = visibility;
    ringRef.current.visible = visibility;

    if (cloudRef.current) cloudRef.current.visible = visibility;
    if (coreParticlesRef.current) coreParticlesRef.current.visible = visibility;
    if (coreLightRef.current) coreLightRef.current.visible = visibility;

    if (!visibility) return;

    // HIGH INTENSITY CORE PULSE
    const pulseSpeed = 2.4;
    const pulseIntensity = Math.pow(Math.sin(time * pulseSpeed), 4);
    const pulseScale = 1 + pulseIntensity * 0.15;
    coreRef.current.scale.setScalar(pulseScale);

    const monolithMaterial = monolithRef.current.material as THREE.MeshPhysicalMaterial;
    monolithMaterial.emissiveIntensity = 2.0 + pulseIntensity * 4.0;
    monolithMaterial.emissive.setRGB(0.1 + pulseIntensity * 0.2, 0.4 + pulseIntensity * 0.4, 1.0);

    if (coreLightRef.current) {
      coreLightRef.current.intensity = 50 + pulseIntensity * 100;
      coreLightRef.current.color.setRGB(0.2, 0.5 + pulseIntensity * 0.3, 1.0);
    }

    // Monolith/Ring movement
    monolithRef.current.rotation.y = time * 0.15;
    ringRef.current.rotation.y = -time * 0.3;
    ringRef.current.rotation.z = Math.sin(time * 0.5) * 0.15;

    // Data Satellites Animation
    let instanceIdx = 0;
    satellites.forEach((sat) => {
      const angle = time * sat.speed + sat.offset;
      const orbitX = Math.cos(angle) * sat.orbitRadius;
      const orbitZ = Math.sin(angle) * sat.orbitRadius;

      sat.clusterVoxels.forEach((v) => {
        tempObject.position.set(orbitX + v.pos.x, v.pos.y * Math.sin(time), orbitZ + v.pos.z);
        tempObject.rotation.set(time, time * 0.5, 0);
        tempObject.scale.setScalar(v.scale * (1 + pulseIntensity * 0.5));
        tempObject.updateMatrix();
        satelliteMeshRef.current!.setMatrixAt(instanceIdx++, tempObject.matrix);
      });
    });
    satelliteMeshRef.current.instanceMatrix.needsUpdate = true;

    // Shell Voxel Animation
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];
      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.1;

      const s = (i % 8 === 0 ? 0.05 : 0.018) * (1 - scrollProgress * 2.8);
      tempObject.scale.setScalar(Math.max(0, s));
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;

    if (coreParticlesRef.current) {
      coreParticlesRef.current.rotation.y = -time * 0.8;
      // Jitter core particles during high pulse
      coreParticlesRef.current.position.y = Math.sin(time * 20) * (pulseIntensity * 0.05);
    }
  });

  return (
    <group>
      <pointLight ref={coreLightRef} intensity={35} distance={25} decay={2} />

      {/* Atmospheric Particle Cloud */}
      <points ref={cloudRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CLOUD_COUNT} array={cloudParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.015} color="#3b82f6" transparent opacity={0.15} sizeAttenuation />
      </points>

      {/* High-Density Data Column Particles */}
      <points ref={coreParticlesRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CORE_PARTICLE_COUNT} array={coreParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.02} 
          color="#93c5fd" 
          transparent 
          opacity={0.6} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* Main Shell Voxels */}
      <instancedMesh ref={meshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#020617" emissive="#3b82f6" emissiveIntensity={0.05} />
      </instancedMesh>

      {/* Data Satellites Voxels */}
      <instancedMesh ref={satelliteMeshRef} args={[null as any, null as any, SATELLITE_CLUSTERS * VOXELS_PER_SATELLITE]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#60a5fa" emissive="#3b82f6" emissiveIntensity={2} />
      </instancedMesh>

      {/* Central Monolithic Pillar */}
      <mesh ref={monolithRef} position={[0, 0, 0]}>
        <boxGeometry args={[0.8, 8, 0.8]} />
        <meshPhysicalMaterial 
          color="#000000"
          metalness={1}
          roughness={0.05}
          transmission={0.95}
          thickness={3}
          emissiveIntensity={1.5}
          transparent
          opacity={0.85}
          reflectivity={1}
        />
      </mesh>

      {/* Inner Energy Sphere */}
      <mesh ref={coreRef}>
        <sphereGeometry args={[1.5, 32, 32]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissiveIntensity={3.0} 
          transparent 
          opacity={0.95}
          roughness={0}
          metalness={1}
        />
      </mesh>

      {/* Data Orbitals */}
      <group ref={ringRef}>
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[3.2, 0.012, 16, 100]} />
          <meshStandardMaterial color="#3b82f6" emissive="#3b82f6" emissiveIntensity={15} transparent opacity={0.4} />
        </mesh>
        <mesh rotation={[Math.PI / 2, 0, 0]} position={[0, 2, 0]}>
          <torusGeometry args={[2.8, 0.008, 16, 100]} />
          <meshStandardMaterial color="#3b82f6" emissive="#3b82f6" emissiveIntensity={8} transparent opacity={0.3} />
        </mesh>
        <mesh rotation={[Math.PI / 2, 0, 0]} position={[0, -2, 0]}>
          <torusGeometry args={[2.8, 0.008, 16, 100]} />
          <meshStandardMaterial color="#3b82f6" emissive="#3b82f6" emissiveIntensity={8} transparent opacity={0.3} />
        </mesh>
      </group>

      {/* Outer Wireframe Cage */}
      <mesh ref={shellRef}>
        <icosahedronGeometry args={[4.2, 1]} />
        <meshStandardMaterial color="#1e40af" emissive="#3b82f6" emissiveIntensity={0.5} wireframe transparent opacity={0.12} />
      </mesh>
    </group>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 3200; // Increased density for "Voxel Earth" feel
const CLOUD_COUNT = 2500;
const CORE_PARTICLE_COUNT = 4500;
const SATELLITE_CLUSTERS = 8;
const VOXELS_PER_SATELLITE = 18;

export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const satelliteMeshRef = useRef<THREE.InstancedMesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const monolithRef = useRef<THREE.Mesh>(null);
  const ringRef = useRef<THREE.Group>(null);
  const coreParticlesRef = useRef<THREE.Points>(null);
  const shellRef = useRef<THREE.Mesh>(null);
  const cloudRef = useRef<THREE.Points>(null);
  const coreLightRef = useRef<THREE.PointLight>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  // Voxel Earth Shell positions (Denser at poles to mimic a globe)
  const positions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.2 + (Math.random() > 0.9 ? 1.0 : 0) + (Math.random() * 0.1);
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  // Orbital Satellites - Distributed across spheres
  const satellites = useMemo(() => {
    return Array.from({ length: SATELLITE_CLUSTERS }).map((_, i) => ({
      orbitRadius: 5.0 + i * 0.6,
      speed: 0.15 + Math.random() * 0.4,
      offset: Math.random() * Math.PI * 2,
      axis: new THREE.Vector3(Math.random() - 0.5, 1, Math.random() - 0.5).normalize(),
      clusterVoxels: Array.from({ length: VOXELS_PER_SATELLITE }).map(() => ({
        pos: new THREE.Vector3((Math.random() - 0.5) * 0.8, (Math.random() - 0.5) * 0.8, (Math.random() - 0.5) * 0.8),
        scale: 0.015 + Math.random() * 0.045
      }))
    }));
  }, []);

  const cloudParticles = useMemo(() => {
    const pos = new Float32Array(CLOUD_COUNT * 3);
    for (let i = 0; i < CLOUD_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 6 + Math.random() * 12;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  const coreParticles = useMemo(() => {
    const pos = new Float32Array(CORE_PARTICLE_COUNT * 3);
    for (let i = 0; i < CORE_PARTICLE_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const r = 0.4 + Math.random() * 2.2;
      const h = (Math.random() - 0.5) * 10;
      pos[i * 3] = r * Math.cos(theta);
      pos[i * 3 + 1] = h;
      pos[i * 3 + 2] = r * Math.sin(theta);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !meshRef.current || !coreRef.current || !shellRef.current || !monolithRef.current || !ringRef.current || !satelliteMeshRef.current) return;
    const time = state.clock.getElapsedTime();

    const visibility = scrollProgress < 0.35;
    groupRef.current.visible = visibility;

    if (!visibility) return;

    // HIGH INTENSITY CORE PULSE (Voxel Earth Rhythm)
    const pulseSpeed = 1.8;
    const pulseIntensity = Math.pow(Math.sin(time * pulseSpeed), 10); // Sharper beat
    const pulseScale = 1 + pulseIntensity * 0.2;
    coreRef.current.scale.setScalar(pulseScale);

    const monolithMaterial = monolithRef.current.material as THREE.MeshPhysicalMaterial;
    monolithMaterial.emissiveIntensity = 1.0 + pulseIntensity * 6.0;
    monolithMaterial.emissive.setRGB(0.05 + pulseIntensity * 0.1, 0.4 + pulseIntensity * 0.5, 0.9);

    if (coreLightRef.current) {
      coreLightRef.current.intensity = 40 + pulseIntensity * 140;
      coreLightRef.current.color.setRGB(0.1, 0.6 + pulseIntensity * 0.4, 1.0);
    }

    // Gentle global rotation
    groupRef.current.rotation.y = time * 0.05;

    // Satellite Animation
    let instanceIdx = 0;
    satellites.forEach((sat) => {
      const angle = time * sat.speed + sat.offset;
      const orbitX = Math.cos(angle) * sat.orbitRadius;
      const orbitZ = Math.sin(angle) * sat.orbitRadius;

      sat.clusterVoxels.forEach((v) => {
        tempObject.position.set(orbitX + v.pos.x, v.pos.y + Math.sin(time * 2 + v.pos.x) * 0.2, orbitZ + v.pos.z);
        tempObject.rotation.set(time * 0.5, time, 0);
        tempObject.scale.setScalar(v.scale * (1 + pulseIntensity * 0.8));
        tempObject.updateMatrix();
        satelliteMeshRef.current!.setMatrixAt(instanceIdx++, tempObject.matrix);
      });
    });
    satelliteMeshRef.current.instanceMatrix.needsUpdate = true;

    // Main Earth Shell Animation
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const x = positions[i * 3];
      const y = positions[i * 3 + 1];
      const z = positions[i * 3 + 2];
      tempObject.position.set(x, y, z);
      tempObject.rotation.y = time * 0.1;

      const distFromPulse = 1 - Math.abs(Math.sin(time - i * 0.001));
      const s = (i % 12 === 0 ? 0.06 : 0.02) * (1 - scrollProgress * 3.0) * (1 + distFromPulse * 0.2);
      tempObject.scale.setScalar(Math.max(0, s));
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;

    // Interior Particle Stream
    if (coreParticlesRef.current) {
      coreParticlesRef.current.rotation.y = -time * 1.2;
      coreParticlesRef.current.scale.setScalar(1 + pulseIntensity * 0.1);
    }

    // Ring Oscillation
    ringRef.current.rotation.y = -time * 0.2;
    ringRef.current.rotation.z = Math.sin(time * 0.5) * 0.1;
  });

  return (
    <group ref={groupRef}>
      <pointLight ref={coreLightRef} intensity={35} distance={30} decay={2} />

      {/* Atmospheric Cloud */}
      <points ref={cloudRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CLOUD_COUNT} array={cloudParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.012} color="#1e40af" transparent opacity={0.1} sizeAttenuation />
      </points>

      {/* Internal Core Data Flow */}
      <points ref={coreParticlesRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={CORE_PARTICLE_COUNT} array={coreParticles} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.018} 
          color="#60a5fa" 
          transparent 
          opacity={0.4} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* The Voxel Earth Shell */}
      <instancedMesh ref={meshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#020617" emissive="#1d4ed8" emissiveIntensity={0.1} />
      </instancedMesh>

      {/* Orbiting Satellites */}
      <instancedMesh ref={satelliteMeshRef} args={[null as any, null as any, SATELLITE_CLUSTERS * VOXELS_PER_SATELLITE]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#3b82f6" emissive="#60a5fa" emissiveIntensity={3} />
      </instancedMesh>

      {/* Central Monolithic Column */}
      <mesh ref={monolithRef} position={[0, 0, 0]}>
        <boxGeometry args={[0.7, 9, 0.7]} />
        <meshPhysicalMaterial 
          color="#000000"
          metalness={1}
          roughness={0}
          transmission={0.98}
          thickness={4}
          emissiveIntensity={1}
          transparent
          opacity={0.9}
        />
      </mesh>

      {/* Inner Heart of the Pantheon */}
      <mesh ref={coreRef}>
        <sphereGeometry args={[1.6, 32, 32]} />
        <meshPhysicalMaterial 
          color="#000000" 
          emissiveIntensity={4.0} 
          transparent 
          opacity={0.98}
          roughness={0}
          metalness={1}
        />
      </mesh>

      {/* Horizon Rings */}
      <group ref={ringRef}>
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[3.4, 0.008, 16, 120]} />
