export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const conduitRef = useRef<THREE.Mesh>(null);
  const staticMatRef = useRef<THREE.ShaderMaterial>(null);
  const pathwaysRef = useRef<THREE.LineSegments>(null);
  const synapsesRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  // Generate Neural Pathways (Lines)
  const pathwayData = useMemo(() => {
    const points = [];
    const nodePositions = [];
    for (let i = 0; i < NEURAL_NODES; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.5 + Math.random() * 0.5;
      nodePositions.push(new THREE.Vector3(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      ));
    }

    const linePoints = [];
    for (let i = 0; i < PATHWAY_COUNT; i++) {
      const start = nodePositions[Math.floor(Math.random() * nodePositions.length)];
      const end = nodePositions[Math.floor(Math.random() * nodePositions.length)];
      linePoints.push(start.x, start.y, start.z, end.x, end.y, end.z);
    }
    return new Float32Array(linePoints);
  }, []);

  // Generate Synaptic Particles (Data Packets)
  const synapseData = useMemo(() => {
    const pos = new Float32Array(SYNAPSE_COUNT * 3);
    const progress = new Float32Array(SYNAPSE_COUNT);
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      progress[i] = Math.random();
    }
    return { pos, progress };
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !conduitRef.current || !pathwaysRef.current || !synapsesRef.current || !coreRef.current) return;
    const time = state.clock.getElapsedTime();

    const isVisible = scrollProgress < 0.35;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    // Update Conduit Shader
    if (staticMatRef.current) {
      staticMatRef.current.uniforms.uTime.value = time;
    }

    // Neural Pulse Animation
    const pulse = Math.pow(Math.sin(time * 2), 6);
    coreRef.current.scale.setScalar(1 + pulse * 0.1);

    // Rotate entire network
    groupRef.current.rotation.y = time * 0.05;
    pathwaysRef.current.rotation.y = time * 0.1;

    // Animate Synapses (Data packets flowing to core)
    const positions = synapsesRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      const p = (synapseData.progress[i] + time * 0.2) % 1.0;
      // Oscillate between shell and core
      const r = 4.0 * (1.0 - p);
      const theta = i * 0.5;
      const phi = i * 0.8;

      positions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      positions[i * 3 + 2] = r * Math.cos(phi);
    }
    synapsesRef.current.geometry.attributes.position.needsUpdate = true;

    // Scroll fade out
    const opacity = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.35);
    groupRef.current.scale.setScalar(1 - opacity);
  });

  return (
    <group ref={groupRef}>
      {/* Central Neural Hub */}
      <mesh ref={coreRef}>
        <icosahedronGeometry args={[1.5, 2]} />
        <meshStandardMaterial 
          color="#000000" 
          emissive="#3b82f6" 
          emissiveIntensity={2} 
          wireframe 
        />
        <pointLight intensity={50} color="#3b82f6" distance={15} />
      </mesh>

      {/* Sentient Data Conduit (Static Column) */}
      <mesh ref={conduitRef} position={[0, 0, 0]}>
        <boxGeometry args={[0.5, 10, 0.5]} />
        <shaderMaterial 
          ref={staticMatRef}
          transparent
          {...staticShader}
        />
      </mesh>

      {/* Synaptic Pathway Web */}
      <lineSegments ref={pathwaysRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={pathwayData.length / 3} 
            array={pathwayData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <lineBasicMaterial color="#1e3a8a" transparent opacity={0.2} />
      </lineSegments>

      {/* Traveling Synapses (Data Particles) */}
      <points ref={synapsesRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={SYNAPSE_COUNT} 
            array={synapseData.pos} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.03} 
          color="#60a5fa" 
          transparent 
          opacity={0.8} 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* Orbital Constraints */}
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[4, 0.005, 16, 100]} />
        <meshBasicMaterial color="#3b82f6" transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

