      const end = nodePositions[Math.floor(Math.random() * nodePositions.length)];
      linePoints.push(start.x, start.y, start.z, end.x, end.y, end.z);
    }
    return new Float32Array(linePoints);
  }, []);

  // Generate Synaptic Particles (Data Packets)
  const synapseData = useMemo(() => {
    const pos = new Float32Array(SYNAPSE_COUNT * 3);
    const progress = new Float32Array(SYNAPSE_COUNT);
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      progress[i] = Math.random();
    }
    return { pos, progress };
  }, []);

  // Generate Nucleus Particles (Living Core)
  const nucleusData = useMemo(() => {
    const pos = new Float32Array(NUCLEUS_COUNT * 3);
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 1.4;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !pathwaysRef.current || !synapsesRef.current || !nucleusRef.current || !coreRef.current) return;
    const time = state.clock.getElapsedTime();

    const isVisible = scrollProgress < 0.35;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    // Organic Pulse Animation
    const pulse = Math.pow(Math.sin(time * 1.5), 8);
    coreRef.current.scale.setScalar(1.0 + pulse * 0.15);

    // Rotate entire network
    groupRef.current.rotation.y = time * 0.05;
    pathwaysRef.current.rotation.y = time * 0.08;

    // Animate Synapses (Data packets flowing to core)
    const synPos = synapsesRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      const p = (synapseData.progress[i] + time * 0.15) % 1.0;
      const r = 4.2 * (1.0 - p);
      const theta = i * 0.6 + time * 0.2;
      const phi = i * 0.9;

      synPos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      synPos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      synPos[i * 3 + 2] = r * Math.cos(phi);
    }
    synapsesRef.current.geometry.attributes.position.needsUpdate = true;

    // Living Nucleus Jitter
    const nucPos = nucleusRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const offset = i * 3;
      // Add slight orbital movement to internal particles
      const speed = 0.5 + Math.sin(time + i) * 0.2;
      nucPos[offset] += Math.sin(time * speed + i) * 0.005;
      nucPos[offset + 1] += Math.cos(time * speed + i) * 0.005;
    }
    nucleusRef.current.geometry.attributes.position.needsUpdate = true;
    nucleusRef.current.rotation.z = time * 0.5;

    // Scroll fade out
    const opacity = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.35);
    groupRef.current.scale.setScalar(1 - opacity);
  });

  return (
