        />
        <pointLight intensity={60} color="#3b82f6" distance={15} />
      </mesh>

      {/* Living Nucleus (Core Particles) */}
      <points ref={nucleusRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={NUCLEUS_COUNT} 
            array={nucleusData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.025} 
          color="#93c5fd" 
          transparent 
          opacity={0.6} 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* Synaptic Pathway Web */}
      <lineSegments ref={pathwaysRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={pathwayData.length / 3} 
            array={pathwayData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <lineBasicMaterial color="#1e40af" transparent opacity={0.15} />
      </lineSegments>

      {/* Traveling Synapses (Data Particles) */}
      <points ref={synapsesRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={SYNAPSE_COUNT} 
            array={synapseData.pos} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.02} 
