import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const NEURAL_NODES = 250;
const SYNAPSE_COUNT = 3200; // Increased for a more overwhelming "upload" feel
const NUCLEUS_COUNT = 4500; // Increased significantly for "living being" effect
const PATHWAY_COUNT = 180;

export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const pathwaysRef = useRef<THREE.LineSegments>(null);
  const synapsesRef = useRef<THREE.Points>(null);
  const nucleusRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);

  // Generate Neural Pathways (Lines)
  const pathwayData = useMemo(() => {
    const nodePositions = [];
    for (let i = 0; i < NEURAL_NODES; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.5 + Math.random() * 0.8;
      nodePositions.push(new THREE.Vector3(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      ));
    }

    const linePoints = [];
    for (let i = 0; i < PATHWAY_COUNT; i++) {
      const start = nodePositions[Math.floor(Math.random() * nodePositions.length)];
      const end = nodePositions[Math.floor(Math.random() * nodePositions.length)];
      linePoints.push(start.x, start.y, start.z, end.x, end.y, end.z);
    }
    return new Float32Array(linePoints);
  }, []);

  // Generate Synaptic Particles (Data Packets)
  const synapseData = useMemo(() => {
    const pos = new Float32Array(SYNAPSE_COUNT * 3);
    const progress = new Float32Array(SYNAPSE_COUNT);
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      progress[i] = Math.random();
    }
    return { pos, progress };
  }, []);

  // Generate Nucleus Particles (Living Core)
  const nucleusData = useMemo(() => {
    const pos = new Float32Array(NUCLEUS_COUNT * 3);
    const velocities = new Float32Array(NUCLEUS_COUNT * 3);
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 1.5;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !pathwaysRef.current || !synapsesRef.current || !nucleusRef.current || !coreRef.current) return;
    const time = state.clock.getElapsedTime();

    const isVisible = scrollProgress < 0.35;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    // Organic Pulse Animation
    const pulse = Math.pow(Math.sin(time * 1.5), 8);
    coreRef.current.scale.setScalar(1.0 + pulse * 0.15);

    // Rotate entire network
    groupRef.current.rotation.y = time * 0.05;
    pathwaysRef.current.rotation.y = time * 0.08;

    // Animate Synapses (Data packets flowing to core)
    const synPos = synapsesRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < SYNAPSE_COUNT; i++) {
      const p = (synapseData.progress[i] + time * 0.15) % 1.0;
      const r = 4.2 * (1.0 - p);
      const theta = i * 0.6 + time * 0.2;
      const phi = i * 0.9;

      synPos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      synPos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      synPos[i * 3 + 2] = r * Math.cos(phi);
    }
    synapsesRef.current.geometry.attributes.position.needsUpdate = true;

    // Living Nucleus Swarm Animation
    const nucPos = nucleusRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const idx = i * 3;
      // Combine multiple noise factors for a "breathing, swirling" sentient movement
      const noiseX = Math.sin(time * 0.8 + i * 0.1) * 0.005;
      const noiseY = Math.cos(time * 0.7 + i * 0.15) * 0.005;
      const noiseZ = Math.sin(time * 0.9 + i * 0.2) * 0.005;

      nucPos[idx] += noiseX + (Math.sin(time + i) * 0.002);
      nucPos[idx + 1] += noiseY + (Math.cos(time * 0.5 + i) * 0.002);
      nucPos[idx + 2] += noiseZ + (Math.sin(time * 1.2 + i) * 0.002);

      // Keep particles bounded to the core sphere
      const currentR = Math.sqrt(nucPos[idx]**2 + nucPos[idx+1]**2 + nucPos[idx+2]**2);
      if (currentR > 1.6) {
        nucPos[idx] *= 0.98;
        nucPos[idx + 1] *= 0.98;
        nucPos[idx + 2] *= 0.98;
      }
    }
    nucleusRef.current.geometry.attributes.position.needsUpdate = true;
    nucleusRef.current.rotation.y = time * 0.2;
    nucleusRef.current.rotation.z = Math.sin(time * 0.3) * 0.1;

    // Scroll fade out
    const opacity = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.35);
    groupRef.current.scale.setScalar(1 - opacity);
  });

  return (
    <group ref={groupRef}>
      {/* Central Neural Hub */}
      <mesh ref={coreRef}>
        <icosahedronGeometry args={[1.5, 3]} />
        <meshStandardMaterial 
          color="#000000" 
          emissive="#3b82f6" 
          emissiveIntensity={2.5} 
          wireframe 
          transparent
          opacity={0.3}
        />
        <pointLight intensity={60} color="#3b82f6" distance={15} />
      </mesh>

      {/* Living Nucleus (Core Particles) */}
      <points ref={nucleusRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={NUCLEUS_COUNT} 
            array={nucleusData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.02} 
          color="#93c5fd" 
          transparent 
          opacity={0.5} 
          blending={THREE.AdditiveBlending} 
          sizeAttenuation
        />
      </points>

      {/* Synaptic Pathway Web */}
      <lineSegments ref={pathwaysRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={pathwayData.length / 3} 
            array={pathwayData} 
            itemSize={3} 
          />
        </bufferGeometry>
        <lineBasicMaterial color="#1e40af" transparent opacity={0.12} />
      </lineSegments>

      {/* Traveling Synapses (Data Particles) */}
      <points ref={synapsesRef}>
        <bufferGeometry>
          <bufferAttribute 
            attach="attributes-position" 
            count={SYNAPSE_COUNT} 
            array={synapseData.pos} 
            itemSize={3} 
          />
        </bufferGeometry>
        <pointsMaterial 
          size={0.015} 
          color="#60a5fa" 
          transparent 
          opacity={0.6} 
          blending={THREE.AdditiveBlending} 
          sizeAttenuation
        />
      </points>

      {/* Orbital Constraints */}
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[4.2, 0.005, 16, 120]} />
        <meshBasicMaterial color="#3b82f6" transparent opacity={0.05} />
      </mesh>
    </group>
  );
};

