import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 3000; 
const NUCLEUS_COUNT = 2500;

export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const voxelMeshRef = useRef<THREE.InstancedMesh>(null);
  const nucleusRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  // Generate Spherical Voxel Positions (Voxel Earth)
  const voxelPositions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.8 + (Math.random() * 0.05); // Slight surface variation
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  // Generate Living Nucleus (Core Particles)
  const nucleusData = useMemo(() => {
    const pos = new Float32Array(NUCLEUS_COUNT * 3);
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 1.4;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !voxelMeshRef.current || !nucleusRef.current || !coreRef.current) return;
    const time = state.clock.getElapsedTime();

    const isVisible = scrollProgress < 0.35;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    // Organic Pulse Animation
    const pulse = Math.pow(Math.sin(time * 1.5), 8);
    coreRef.current.scale.setScalar(1.0 + pulse * 0.15);

    // Rotate Earth Shell
    groupRef.current.rotation.y = time * 0.08;

    // Update Voxel Instances
    for (let i = 0; i < VOXEL_COUNT; i++) {
      tempObject.position.set(
        voxelPositions[i * 3],
        voxelPositions[i * 3 + 1],
        voxelPositions[i * 3 + 2]
      );
      tempObject.rotation.set(time * 0.1, time * 0.2, 0);

      // Dynamic scaling for "signal" effect
      const wave = Math.sin(time * 2 + i * 0.1) * 0.01;
      const s = 0.035 + wave;
      tempObject.scale.setScalar(s);

      tempObject.updateMatrix();
      voxelMeshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    voxelMeshRef.current.instanceMatrix.needsUpdate = true;

    // Living Nucleus Swarm
    const nucPos = nucleusRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const idx = i * 3;
      const noiseX = Math.sin(time * 0.8 + i) * 0.004;
      const noiseY = Math.cos(time * 0.7 + i) * 0.004;
      nucPos[idx] += noiseX;
      nucPos[idx + 1] += noiseY;
    }
    nucleusRef.current.geometry.attributes.position.needsUpdate = true;
    nucleusRef.current.rotation.z = time * 0.3;

    // Scroll fade out
    const opacity = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.35);
    groupRef.current.scale.setScalar(1 - opacity);
  });

  return (
    <group ref={groupRef}>
      {/* Voxel Earth Shell */}
      <instancedMesh ref={voxelMeshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial 
          color="#1e3a8a" 
          emissive="#3b82f6" 
          emissiveIntensity={0.4} 
          metalness={1} 
          roughness={0.2}
        />
      </instancedMesh>

      {/* Internal Sentient Nucleus */}
      <points ref={nucleusRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={NUCLEUS_COUNT} array={nucleusData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.02} color="#93c5fd" transparent opacity={0.6} blending={THREE.AdditiveBlending} />
      </points>

      {/* Core Intelligence Hub */}
      <mesh ref={coreRef}>
        <icosahedronGeometry args={[1.5, 3]} />
        <meshStandardMaterial color="#000000" emissive="#3b82f6" emissiveIntensity={3} wireframe transparent opacity={0.3} />
        <pointLight intensity={50} color="#3b82f6" distance={15} />
      </mesh>

      {/* Atmosphere Ring */}
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[4.2, 0.002, 16, 100]} />
        <meshBasicMaterial color="#3b82f6" transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

