import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const ATOMIC_COUNT = 8000;
const STAR_COUNT = 3000;
const FRONTIER_STAR_COUNT = 2500;

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const atomicRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Group>(null);
  const starsRef = useRef<THREE.Points>(null);
  const frontierStarsRef = useRef<THREE.Points>(null);

  // Generate Atomic Particle Swarm (The beginning and end)
  const atomicData = useMemo(() => {
    const pos = new Float32Array(ATOMIC_COUNT * 3);
    const sizes = new Float32Array(ATOMIC_COUNT);
    const opacities = new Float32Array(ATOMIC_COUNT);
    const colors = new Float32Array(ATOMIC_COUNT * 3);

    const colorPalette = [
      new THREE.Color('#ffffff'), // Pure Spirit
      new THREE.Color('#a855f7'), // Void Violet
      new THREE.Color('#38bdf8'), // Ethereal Cyan
      new THREE.Color('#1e1b4b'), // Deep Space
    ];

    for (let i = 0; i < ATOMIC_COUNT; i++) {
      // Large spherical scatter
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 40 + Math.random() * 180;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -100 - (Math.random() * 200);

      sizes[i] = 0.1 + Math.random() * 0.8;
      opacities[i] = 0.2 + Math.random() * 0.8;

      const c = colorPalette[Math.floor(Math.random() * colorPalette.length)];
      colors[i * 3] = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }
    return { pos, sizes, colors, opacities };
  }, []);

  const starData = useMemo(() => {
    const pos = new Float32Array(STAR_COUNT * 3);
    for (let i = 0; i < STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 400 + Math.random() * 200;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi) - 200;
    }
    return pos;
  }, []);

  const frontierStarData = useMemo(() => {
    const pos = new Float32Array(FRONTIER_STAR_COUNT * 3);
    for (let i = 0; i < FRONTIER_STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 50 + Math.random() * 150;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -550; 
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress > 0.8;
    const frontierFactor = THREE.MathUtils.smoothstep(scrollProgress, 0.95, 1.0);

    if (atomicRef.current) {
      atomicRef.current.visible = visible;
      atomicRef.current.rotation.z = time * 0.02;
      atomicRef.current.rotation.y = time * 0.01;

      // Make particles "shimmer" or "glitter"
      const mat = atomicRef.current.material as THREE.PointsMaterial;
      mat.opacity = 0.3 + Math.sin(time * 5) * 0.1;
    }

    if (coreRef.current) {
      coreRef.current.visible = scrollProgress > 0.92;
      coreRef.current.rotation.y = time * 0.1;
      const pulse = 1 + Math.sin(time * 3) * 0.05;
      coreRef.current.scale.setScalar(pulse);
    }

    if (starsRef.current) {
      starsRef.current.visible = visible;
      starsRef.current.rotation.y = time * 0.001;
    }

    if (frontierStarsRef.current) {
      frontierStarsRef.current.visible = frontierFactor > 0.01;
      frontierStarsRef.current.rotation.z = -time * 0.1;
      frontierStarsRef.current.position.z = -100 * (1 - frontierFactor);
    }
  });

  return (
    <group>
      {/* The Atomic Swarm */}
      <points ref={atomicRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={ATOMIC_COUNT} array={atomicData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={ATOMIC_COUNT} array={atomicData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial 
          size={0.4} 
          vertexColors 
          transparent 
          opacity={0.6} 
          sizeAttenuation 
          blending={THREE.AdditiveBlending} 
        />
      </points>

      {/* Starry Backdrop */}
      <points ref={starsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={STAR_COUNT} array={starData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.15} color="#ffffff" transparent opacity={0.4} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Frontier Horizon - The final glowing atom field */}
      <points ref={frontierStarsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={FRONTIER_STAR_COUNT} array={frontierStarData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={1.2} color="#ffffff" transparent opacity={0.8} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* Final Singularity Core */}
      <group ref={coreRef} position={[0, 0, -220]}>
        <mesh>
          <icosahedronGeometry args={[14, 3]} />
          <meshStandardMaterial color="#7c3aed" emissive="#a855f7" emissiveIntensity={6} wireframe transparent opacity={0.6} />
        </mesh>
        <mesh rotation={[Math.PI/2, 0, 0]}>
          <torusKnotGeometry args={[20, 0.4, 128, 16]} />
          <meshStandardMaterial color="#4c1d95" emissive="#7c3aed" emissiveIntensity={3} wireframe transparent opacity={0.3} />
        </mesh>
        <pointLight intensity={300} color="#a855f7" distance={800} decay={2} />
      </group>

      {/* Cosmic Wall */}
      <mesh position={[0, 0, -600]}>
        <planeGeometry args={[30000, 30000]} />
        <meshBasicMaterial color="#000000" />
      </mesh>
    </group>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const ATOMIC_COUNT = 10000; // Increased for ultimate density
const HEART_COUNT = 5000;   // The central singularity of light
const STAR_COUNT = 3000;

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const atomicRef = useRef<THREE.Points>(null);
  const heartRef = useRef<THREE.Points>(null);
  const starsRef = useRef<THREE.Points>(null);

  // Generate the "Alpha & Omega" Atomic Swarm
  const atomicData = useMemo(() => {
    const pos = new Float32Array(ATOMIC_COUNT * 3);
    const colors = new Float32Array(ATOMIC_COUNT * 3);
    const randomness = new Float32Array(ATOMIC_COUNT);

    const palette = [
      new THREE.Color('#ffffff'), // Alpha
      new THREE.Color('#a855f7'), // Void
      new THREE.Color('#22d3ee'), // Omega
    ];

    for (let i = 0; i < ATOMIC_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 30 + Math.random() * 250;

      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -100 - (Math.random() * 400);

      const color = palette[Math.floor(Math.random() * palette.length)];
      colors[i * 3] = color.r;
      colors[i * 3 + 1] = color.g;
      colors[i * 3 + 2] = color.b;

      randomness[i] = Math.random();
    }
    return { pos, colors, randomness };
  }, []);

  // Generate the Singularity Heart (The core that replaces geometry)
  const heartData = useMemo(() => {
    const pos = new Float32Array(HEART_COUNT * 3);
    for (let i = 0; i < HEART_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 12; // Tight central core
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  const starData = useMemo(() => {
    const pos = new Float32Array(STAR_COUNT * 3);
    for (let i = 0; i < STAR_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 500 + Math.random() * 500;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi) - 300;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const isLevel5 = scrollProgress > 0.8;
    const expansion = THREE.MathUtils.smoothstep(scrollProgress, 0.9, 1.0);

    // Animate Main Atomic Swarm
    if (atomicRef.current) {
      atomicRef.current.visible = isLevel5;
      atomicRef.current.rotation.z = time * 0.05;
      atomicRef.current.rotation.y = time * 0.02;

      // Twinkle Logic
      const mat = atomicRef.current.material as THREE.PointsMaterial;
      mat.size = 0.3 + Math.sin(time * 4) * 0.1;
      // At the very end, make them explode outwards
      atomicRef.current.scale.setScalar(1 + expansion * 15);
    }

    // Animate the Singularity Heart
    if (heartRef.current) {
      heartRef.current.visible = scrollProgress > 0.92;
      heartRef.current.rotation.y = -time * 0.5;
      heartRef.current.rotation.x = time * 0.2;

      const pulse = 1 + Math.sin(time * 10) * 0.2;
      heartRef.current.scale.setScalar(pulse * (1 + expansion * 20));
    }

    if (starsRef.current) {
      starsRef.current.visible = isLevel5;
      starsRef.current.rotation.y = time * 0.005;
    }
  });

  return (
    <group>
      {/* Background Star Field */}
      <points ref={starsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={STAR_COUNT} array={starData} itemSize={3} />
