import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 3000; 
const NUCLEUS_COUNT = 4500;

export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const voxelMeshRef = useRef<THREE.InstancedMesh>(null);
  const nucleusRef = useRef<THREE.Points>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const voxelPositions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.8 + (Math.random() * 0.05); 
      pos.push(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi)
      );
    }
    return pos;
  }, []);

  const nucleusData = useMemo(() => {
    const pos = new Float32Array(NUCLEUS_COUNT * 3);
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 1.5;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !voxelMeshRef.current || !nucleusRef.current || !coreRef.current) return;
    const time = state.clock.getElapsedTime();

    const isVisible = scrollProgress < 0.35;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    const pulse = Math.pow(Math.sin(time * 1.2), 10);
    coreRef.current.scale.setScalar(1.0 + pulse * 0.2);
    groupRef.current.rotation.y = time * 0.08;

    for (let i = 0; i < VOXEL_COUNT; i++) {
      tempObject.position.set(
        voxelPositions[i * 3],
        voxelPositions[i * 3 + 1],
        voxelPositions[i * 3 + 2]
      );
      tempObject.rotation.set(time * 0.2, time * 0.3, 0);
      const wave = Math.sin(time * 3 + i * 0.1) * 0.01;
      const s = 0.035 + wave;
      tempObject.scale.setScalar(s);
      tempObject.updateMatrix();
      voxelMeshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    voxelMeshRef.current.instanceMatrix.needsUpdate = true;

    const nucPos = nucleusRef.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < NUCLEUS_COUNT; i++) {
      const idx = i * 3;
      nucPos[idx] += Math.sin(time * 2 + i) * 0.006;
      nucPos[idx + 1] += Math.cos(time * 2.5 + i) * 0.006;
      nucPos[idx + 2] += Math.sin(time * 1.8 + i) * 0.006;
      const currentR = Math.sqrt(nucPos[idx]**2 + nucPos[idx+1]**2 + nucPos[idx+2]**2);
      if (currentR > 1.6) {
        nucPos[idx] *= 0.95; nucPos[idx + 1] *= 0.95; nucPos[idx + 2] *= 0.95;
      }
    }
    nucleusRef.current.geometry.attributes.position.needsUpdate = true;

    const opacity = THREE.MathUtils.smoothstep(scrollProgress, 0.25, 0.35);
    groupRef.current.scale.setScalar(1 - opacity);
  });

  return (
    <group ref={groupRef}>
      <instancedMesh ref={voxelMeshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#1e3a8a" emissive="#3b82f6" emissiveIntensity={0.6} metalness={1} roughness={0.1} />
      </instancedMesh>
      <points ref={nucleusRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={NUCLEUS_COUNT} array={nucleusData} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.025} color="#93c5fd" transparent opacity={0.7} blending={THREE.AdditiveBlending} />
      </points>
      <mesh ref={coreRef}>
        <icosahedronGeometry args={[1.5, 3]} />
        <meshStandardMaterial color="#000000" emissive="#3b82f6" emissiveIntensity={4} wireframe transparent opacity={0.4} />
      </mesh>
      {/* Education Ring Label Decor */}
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[4.2, 0.01, 16, 100]} />
        <meshBasicMaterial color="#3b82f6" transparent opacity={0.2} />
      </mesh>
    </group>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const ATOMIC_COUNT = 15000; // Extreme density for Level 5
const HEART_COUNT = 8000;   // The core of light
const STAR_COUNT = 5000;

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const atomicRef = useRef<THREE.Points>(null);
  const heartRef = useRef<THREE.Points>(null);
  const starsRef = useRef<THREE.Points>(null);

  // Generate the Atomic Pantheon Swarm
  const atomicData = useMemo(() => {
    const pos = new Float32Array(ATOMIC_COUNT * 3);
    const colors = new Float32Array(ATOMIC_COUNT * 3);
    const palette = [
      new THREE.Color('#ffffff'), // The Alpha (Spirit)
      new THREE.Color('#a855f7'), // The Void (Data)
      new THREE.Color('#22d3ee'), // The Omega (Logic)
    ];

    for (let i = 0; i < ATOMIC_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 20 + Math.random() * 300;

      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -150 - (Math.random() * 500);

      const color = palette[Math.floor(Math.random() * palette.length)];
      colors[i * 3] = color.r;
      colors[i * 3 + 1] = color.g;
      colors[i * 3 + 2] = color.b;
    }
    return { pos, colors };
  }, []);

  const heartData = useMemo(() => {
    const pos = new Float32Array(HEART_COUNT * 3);
    for (let i = 0; i < HEART_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * 15;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return pos;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const isLevel5 = scrollProgress > 0.8;
    const expansion = THREE.MathUtils.smoothstep(scrollProgress, 0.9, 1.0);

    if (atomicRef.current) {
      atomicRef.current.visible = isLevel5;
      atomicRef.current.rotation.z = time * 0.03;
      // High-frequency "shimmer" or "glitter"
      const mat = atomicRef.current.material as THREE.PointsMaterial;
      mat.size = 0.4 + Math.sin(time * 6) * 0.2;
      atomicRef.current.scale.setScalar(1 + expansion * 20);
    }

    if (heartRef.current) {
      heartRef.current.visible = scrollProgress > 0.9;
      heartRef.current.rotation.y = time * 0.8;
      const pulse = 1 + Math.sin(time * 12) * 0.3;
      heartRef.current.scale.setScalar(pulse * (1 + expansion * 25));
    }
  });

  return (
    <group>
      {/* Background Starscape */}
      <points ref={starsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={STAR_COUNT} array={new Float32Array(STAR_COUNT * 3).map(() => (Math.random() - 0.5) * 1000)} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.15} color="#ffffff" transparent opacity={0.2} blending={THREE.AdditiveBlending} />
      </points>

      {/* The Shimmering Atomic Swarm */}
      <points ref={atomicRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={ATOMIC_COUNT} array={atomicData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={ATOMIC_COUNT} array={atomicData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.6} vertexColors transparent opacity={0.9} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      {/* The Central Singularity Heart (Replacing geometric shapes) */}
      <group position={[0, 0, -300]}>
        <points ref={heartRef}>
          <bufferGeometry>
            <bufferAttribute attach="attributes-position" count={HEART_COUNT} array={heartData} itemSize={3} />
          </bufferGeometry>
          <pointsMaterial size={0.12} color="#ffffff" transparent opacity={1.0} sizeAttenuation blending={THREE.AdditiveBlending} />
        </points>
        <pointLight intensity={800} color="#ffffff" distance={1500} decay={1.2} />
        <pointLight intensity={400} color="#a855f7" distance={1000} decay={1.8} />
      </group>

      <mesh position={[0, 0, -1200]}>
        <planeGeometry args={[20000, 20000]} />
        <meshBasicMaterial color="#000000" />
      </mesh>
    </group>
  );
};

