      <div className={`transition-all duration-1000 fixed bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center ${scrollProgress < 0.05 ? 'opacity-100' : 'opacity-0 translate-y-20'}`}>
        <div className="w-[1px] h-12 bg-gradient-to-b from-blue-500 to-transparent" />
        <span className="text-[8px] text-blue-400 tracking-[0.5em] uppercase mt-2">Dive Into The Verse</span>
      </div>

      {/* Grid Overlay lines */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none border-[1px] border-blue-900/30 grid grid-cols-12 grid-rows-12">
        {Array.from({ length: 144 }).map((_, i) => (
          <div key={i} className="border-[0.5px] border-blue-900/10" />
        ))}
      </div>
    </div>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const VOXEL_COUNT = 2500; 
const NUCLEUS_COUNT = 4000;

export const VoxelWorld: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const voxelMeshRef = useRef<THREE.InstancedMesh>(null);
  const nucleusRef = useRef<THREE.Points>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const tempObject = new THREE.Object3D();

  const voxelPositions = useMemo(() => {
    const pos = [];
    for (let i = 0; i < VOXEL_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 3.5 + (Math.random() * 0.1); 
      pos.push(r * Math.sin(phi) * Math.cos(theta), r * Math.sin(phi) * Math.sin(theta), r * Math.cos(phi));
    }
    return pos;
  }, []);

  useFrame((state) => {
    if (!groupRef.current || !voxelMeshRef.current || !nucleusRef.current) return;
    const time = state.clock.getElapsedTime();
    const isVisible = scrollProgress < 0.3;
    groupRef.current.visible = isVisible;
    if (!isVisible) return;

    groupRef.current.rotation.y = time * 0.1;

    for (let i = 0; i < VOXEL_COUNT; i++) {
      tempObject.position.set(voxelPositions[i * 3], voxelPositions[i * 3 + 1], voxelPositions[i * 3 + 2]);
      tempObject.rotation.set(time * 0.2, time * 0.3, 0);
      const s = 0.03 + Math.sin(time * 2 + i) * 0.005;
      tempObject.scale.setScalar(s);
      tempObject.updateMatrix();
      voxelMeshRef.current.setMatrixAt(i, tempObject.matrix);
    }
    voxelMeshRef.current.instanceMatrix.needsUpdate = true;

    groupRef.current.scale.setScalar(1 - THREE.MathUtils.smoothstep(scrollProgress, 0.2, 0.3));
  });

  return (
    <group ref={groupRef}>
      <instancedMesh ref={voxelMeshRef} args={[null as any, null as any, VOXEL_COUNT]}>
        <boxGeometry args={[1, 1, 1]} />
        <meshStandardMaterial color="#1e40af" emissive="#3b82f6" emissiveIntensity={0.8} />
      </instancedMesh>

      <points ref={nucleusRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={NUCLEUS_COUNT} array={new Float32Array(NUCLEUS_COUNT * 3).map(() => (Math.random() - 0.5) * 4)} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.02} color="#93c5fd" transparent opacity={0.6} blending={THREE.AdditiveBlending} />
      </points>

      {/* Academic Orbit Nodes */}
      <group>
        <EducationNode position={[6, 2, 0]} label="VIT_2027" scale={0.8} />
        <EducationNode position={[-6, -1, 0]} label="HS_2022" scale={0.5} />
      </group>

      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[5, 0.005, 16, 120]} />
        <meshBasicMaterial color="#3b82f6" transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

const EducationNode: React.FC<{position: [number, number, number], label: string, scale: number}> = ({position, scale}) => {
  const meshRef = useRef<THREE.Mesh>(null);
  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += 0.01;
      meshRef.current.position.y += Math.sin(state.clock.elapsedTime + position[0]) * 0.005;
    }
  });
  return (
    <mesh ref={meshRef} position={position}>
      <icosahedronGeometry args={[scale, 0]} />
      <meshStandardMaterial color="#3b82f6" emissive="#3b82f6" emissiveIntensity={2} wireframe />
    </mesh>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame, useLoader, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

export const DreamMonolith: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null);
  const scrollProgress = useStore((state) => state.scrollProgress);
  const dreamTextureUrl = useStore((state) => state.dreamTextureUrl);
  const { camera } = useThree();

  const texture = dreamTextureUrl ? useLoader(THREE.TextureLoader, dreamTextureUrl) : null;
  if (texture) texture.wrapS = texture.wrapT = THREE.RepeatWrapping;

  const shards = useMemo(() => {
    const arr = [];
    for (let i = 0; i < 20; i++) {
      arr.push({
        angle: (i / 20) * Math.PI * 2,
        radius: 3 + Math.random() * 2,
        speed: 0.2 + Math.random() * 0.3,
        offsetY: (Math.random() - 0.5) * 4
      });
    }
    return arr;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const visible = scrollProgress >= 0.2 && scrollProgress <= 0.5;

    if (meshRef.current) {
      meshRef.current.visible = visible;
      meshRef.current.rotation.y = time * 0.1;
      const s = THREE.MathUtils.smoothstep(scrollProgress, 0.2, 0.35) * 1.5;
      meshRef.current.scale.set(s, s * 2, s);

      if (texture) {
        texture.offset.x = THREE.MathUtils.lerp(texture.offset.x, -camera.position.x * 0.05, 0.05);
        texture.offset.y = THREE.MathUtils.lerp(texture.offset.y, -camera.position.y * 0.05, 0.05);
      }
    }
  });

  return (
    <group position={[0, 0, -8]}>
      <mesh ref={meshRef}>
        <boxGeometry args={[1, 2, 0.1]} />
        <meshStandardMaterial 
          map={texture || undefined} 
          color={texture ? "#ffffff" : "#020617"}
          metalness={1}
          roughness={0}
          emissive={texture ? "#ffffff" : "#3b82f6"}
          emissiveIntensity={texture ? 1.5 : 0.1}
        />
        <pointLight intensity={15} color="#ffffff" distance={10} />
      </mesh>

      {/* Skill Shards Orbiting the Neural Library */}
      <group>
        {shards.map((s, i) => (
          <SkillShard key={i} {...s} visible={scrollProgress > 0.25 && scrollProgress < 0.45} />
        ))}
      </group>
    </group>
  );
};

const SkillShard: React.FC<any> = ({ angle, radius, speed, offsetY, visible }) => {
  const meshRef = useRef<THREE.Mesh>(null);
  useFrame((state) => {
    if (meshRef.current) {
      const time = state.clock.getElapsedTime();
      const currentAngle = angle + time * speed;
      meshRef.current.position.set(Math.cos(currentAngle) * radius, offsetY + Math.sin(time * 0.5) * 0.2, Math.sin(currentAngle) * radius);
      meshRef.current.rotation.x += 0.01;
      meshRef.current.rotation.y += 0.01;
      meshRef.current.visible = visible;
    }
  });
  return (
    <mesh ref={meshRef}>
      <boxGeometry args={[0.2, 0.4, 0.01]} />
      <meshStandardMaterial color="#3b82f6" emissive="#60a5fa" emissiveIntensity={4} transparent opacity={0.6} metalness={1} />
    </mesh>
  );
};

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useStore } from '../../store';

const ATOMIC_COUNT = 20000; 
const SINGULARITY_COUNT = 10000;

export const DeepVoid: React.FC = () => {
  const scrollProgress = useStore((state) => state.scrollProgress);
  const atomicRef = useRef<THREE.Points>(null);
  const singularityRef = useRef<THREE.Points>(null);

  const atomicData = useMemo(() => {
    const pos = new Float32Array(ATOMIC_COUNT * 3);
    const colors = new Float32Array(ATOMIC_COUNT * 3);
    const palette = [
      new THREE.Color('#ffffff'), // Alpha
      new THREE.Color('#a855f7'), // Void
      new THREE.Color('#22d3ee'), // Omega
    ];

    for (let i = 0; i < ATOMIC_COUNT; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 20 + Math.random() * 400;
      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = -200 - (Math.random() * 600);
      const color = palette[Math.floor(Math.random() * palette.length)];
      colors[i * 3] = color.r; colors[i * 3 + 1] = color.g; colors[i * 3 + 2] = color.b;
    }
    return { pos, colors };
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const isLevel5 = scrollProgress > 0.8;
    const expansion = THREE.MathUtils.smoothstep(scrollProgress, 0.85, 1.0);

    if (atomicRef.current) {
      atomicRef.current.visible = isLevel5;
      atomicRef.current.rotation.z = time * 0.05;
      const mat = atomicRef.current.material as THREE.PointsMaterial;
      mat.size = 0.5 + Math.sin(time * 8) * 0.25; // Glitter oscillation
      atomicRef.current.scale.setScalar(1 + expansion * 30);
    }

    if (singularityRef.current) {
      singularityRef.current.visible = scrollProgress > 0.92;
      singularityRef.current.rotation.y = time * 1.5;
      singularityRef.current.scale.setScalar(1 + expansion * 50);
    }
  });

  return (
    <group>
      <points ref={atomicRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={ATOMIC_COUNT} array={atomicData.pos} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={ATOMIC_COUNT} array={atomicData.colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.5} vertexColors transparent opacity={0.9} sizeAttenuation blending={THREE.AdditiveBlending} />
      </points>

      <group position={[0, 0, -400]}>
        <points ref={singularityRef}>
          <bufferGeometry>
            <bufferAttribute attach="attributes-position" count={SINGULARITY_COUNT} array={new Float32Array(SINGULARITY_COUNT * 3).map(() => (Math.random() - 0.5) * 20)} itemSize={3} />
          </bufferGeometry>
          <pointsMaterial size={0.1} color="#ffffff" transparent opacity={1} blending={THREE.AdditiveBlending} />
        </points>
        <pointLight intensity={1000} color="#ffffff" distance={2000} decay={1.5} />
        <pointLight intensity={500} color="#22d3ee" distance={1200} decay={2} />
      </group>

      <mesh position={[0, 0, -1500]}>
        <planeGeometry args={[30000, 30000]} />
        <meshBasicMaterial color="#000000" />
      </mesh>
    </group>
  );
};
